import { Message, KeyConfig, GenerationConfig, ModelProvider, ModelInfo, Language } from "../types";
import { OpenAIService } from "./openaiService";
import { GoogleService } from "./googleService";
import { OllamaService } from "./ollamaService";
import { t } from "../utils/i18n";

/**
 * 队列任务接口定义
 */
interface RequestTask {
  execute: () => Promise<any>;
  resolve: (value: any) => void;
  reject: (reason?: any) => void;
  abortSignal?: AbortSignal;
}

/**
 * LLM 核心服务类：处理多提供商交互。
 * 包含：API 密钥轮询、负载均衡、请求队列处理。
 */
export class LLMService {
  private keys: KeyConfig[] = [];
  private keyIndex: number = 0;
  private keyUsageCount: number = 0;

  // 队列管理状态
  private requestQueue: RequestTask[] = [];
  private isProcessingQueue: boolean = false;

  private openAIService: OpenAIService;
  private googleService: GoogleService;
  private ollamaService: OllamaService;
  private onKeyError?: (id: string, errorCode?: string, isFatal?: boolean) => void;

  constructor(initialKeys: KeyConfig[], onKeyError?: (id: string, errorCode?: string, isFatal?: boolean) => void) {
    this.updateKeys(initialKeys);
    this.openAIService = new OpenAIService();
    this.googleService = new GoogleService();
    this.ollamaService = new OllamaService();
    this.onKeyError = onKeyError;
  }

  /**
   * 更新 API 密钥池
   */
  public updateKeys(newKeys: KeyConfig[]) {
    this.keys = newKeys;
    if (this.keyIndex >= this.keys.length) {
        this.keyIndex = 0;
        this.keyUsageCount = 0;
    }
  }

  /**
   * 将任务推入队列并触发处理逻辑
   */
  private async enqueueTask<T>(execute: () => Promise<T>, abortSignal?: AbortSignal): Promise<T> {
    return new Promise((resolve, reject) => {
      // 检查如果已经取消，则不入队
      if (abortSignal?.aborted) {
        return reject(new Error("Aborted by user"));
      }

      this.requestQueue.push({
        execute,
        resolve,
        reject,
        abortSignal
      });

      this.processQueue();
    });
  }

  /**
   * 顺序处理队列中的任务 (FIFO)
   */
  private async processQueue() {
    if (this.isProcessingQueue || this.requestQueue.length === 0) return;

    this.isProcessingQueue = true;

    while (this.requestQueue.length > 0) {
      const task = this.requestQueue.shift();
      if (!task) continue;

      // 如果任务在排队期间已被取消，直接跳过
      if (task.abortSignal?.aborted) {
        task.reject(new Error("Aborted by user"));
        continue;
      }

      try {
        const result = await task.execute();
        task.resolve(result);
      } catch (error) {
        task.reject(error);
      }
    }

    this.isProcessingQueue = false;
  }

  /**
   * 获取模型列表（加入队列处理）
   */
  public async listModels(keyConfig: KeyConfig): Promise<ModelInfo[]> {
    return this.enqueueTask(async () => {
      if (keyConfig.provider === 'openai') {
          if (!keyConfig.baseUrl) throw new Error("Base URL is required for OpenAI provider");
          return await this.openAIService.listModels(keyConfig.key, keyConfig.baseUrl);
      } else if (keyConfig.provider === 'ollama') {
          return await this.ollamaService.listModels(keyConfig.baseUrl || '', keyConfig.key);
      } else {
          return await this.googleService.listModels(keyConfig.key);
      }
    });
  }

  /**
   * 测试连接（加入队列处理）
   */
  public async testConnection(keyConfig: KeyConfig): Promise<boolean> {
    return this.enqueueTask(async () => {
      const modelToUse = keyConfig.model || (keyConfig.provider === 'openai' ? 'gpt-3.5-turbo' : 'gemini-2.5-flash');
      try {
          if (keyConfig.provider === 'openai') {
              if (!keyConfig.baseUrl) return false;
              return await this.openAIService.testChat(keyConfig.key, keyConfig.baseUrl, modelToUse);
          } else if (keyConfig.provider === 'ollama') {
              return await this.ollamaService.testConnection(keyConfig.baseUrl || '', keyConfig.key);
          } else {
              return await this.googleService.testConnection(keyConfig.key, modelToUse);
          }
      } catch (e) {
          return false;
      }
    });
  }

  /**
   * 轮询策略：获取下一个可用的 API 密钥
   */
  private getNextAvailableKey(lang: Language): KeyConfig {
    const activeKeys = this.keys.filter(k => k.isActive);

    if (activeKeys.length === 0) {
      throw new Error(t('error.no_active_keys', lang));
    }

    const attempts = activeKeys.length;
    let selectedKey: KeyConfig | null = null;
    let selectedIndex = -1;

    for (let i = 0; i < attempts; i++) {
        const idx = (this.keyIndex + i) % activeKeys.length;
        const candidate = activeKeys[idx];

        // 检查冷却时间
        if (candidate.isRateLimited && Date.now() - candidate.lastUsed < 60000) {
            continue; 
        }

        // 检查轮询使用限制
        if (i === 0 && this.keyUsageCount >= (candidate.usageLimit || 1)) {
             continue; 
        }

        selectedKey = candidate;
        selectedIndex = idx;
        break;
    }

    if (!selectedKey) {
        selectedIndex = (this.keyIndex + 1) % activeKeys.length;
        selectedKey = activeKeys[selectedIndex];
    }

    if (this.keyIndex !== selectedIndex) {
        this.keyIndex = selectedIndex;
        this.keyUsageCount = 0;
    }

    this.keyUsageCount++;
    return selectedKey;
  }

  private getKeyDisplayIndex(id: string): number {
      return this.keys.findIndex(k => k.id === id) + 1;
  }

  private getErrorMessage(error: any, lang: Language): string {
      const status = error.status || error.statusCode;
      const msg = error.message?.toLowerCase() || '';

      if (status === 401 || msg.includes('401') || msg.includes('invalid api key')) return t('error.invalid_api_key', lang);
      if (status === 402 || msg.includes('402') || msg.includes('billing')) return t('error.billing_required', lang);
      if (status === 403 || msg.includes('403') || msg.includes('permission denied')) return t('error.permission_denied', lang);
      if (status === 404 || msg.includes('404') || msg.includes('not found')) return t('error.model_not_found', lang);
      if (status === 429 || msg.includes('429') || msg.includes('quota') || msg.includes('rate limit')) return t('error.quota_exceeded', lang);
      if (status === 400 || msg.includes('400')) {
          if (msg.includes('safety') || error.isSafety) return t('error.safety_block', lang);
          if (msg.includes('context')) return t('error.context_length_exceeded', lang);
          return t('error.bad_request', lang);
      }
      if (status === 500 || status === 502 || status === 503 || msg.includes('500')) return t('error.server_error', lang);
      if (status === 0 || msg.includes('network') || msg.includes('fetch')) return t('error.network_issue', lang);
      if (msg.includes('refused')) return t('error.connection_refused', lang);

      return error.message || t('error.unexpected_error', lang);
  }

  /**
   * 流式响应聊天（加入队列处理）
   * 处理逻辑：在任务执行时才进行密钥获取和重试，确保队列排队不会浪费重试次数。
   */
  public async streamChatResponse(
    _ignoredGlobalModelId: string, 
    history: Message[],
    newMessage: string,
    images: string[] | undefined,
    systemInstruction: string | undefined,
    generationConfig: GenerationConfig,
    onChunk?: (text: string) => void,
    abortSignal?: AbortSignal,
    lang: Language = 'en'
  ): Promise<{ text: string, usedKeyIndex: number, provider: ModelProvider, usedModel: string }> {

    // 使用队列包裹整个聊天逻辑
    return this.enqueueTask(async () => {
        const activeKeysCount = this.keys.filter(k => k.isActive).length;
        const maxRetries = Math.max(activeKeysCount * 2, 2); 
        let attempts = 0;
        const validHistory = history.filter(msg => (msg.text && msg.text.trim().length > 0) || (msg.images && msg.images.length > 0));

        let lastError: any = null;

        while (attempts < maxRetries) {
            let keyConfig: KeyConfig;
            try {
                keyConfig = this.getNextAvailableKey(lang);
            } catch (e: any) {
                throw e;
            }

            const modelToUse = keyConfig.model || _ignoredGlobalModelId || 'gemini-3-flash-preview';

            try {
                let text = "";

                // 1. 检查是否是图像生成模型
                if (keyConfig.provider === 'google' && modelToUse.toLowerCase().includes('imagen')) {
                     text = await this.googleService.generateImage(keyConfig.key, modelToUse, newMessage);
                } 
                // 2. OpenAI 兼容提供商
                else if (keyConfig.provider === 'openai') {
                    if (!keyConfig.baseUrl) throw new Error(t('error.base_url_required', lang));
                    text = await this.openAIService.streamChat(
                        keyConfig.key, keyConfig.baseUrl, modelToUse, validHistory, 
                        newMessage, images, systemInstruction, generationConfig, onChunk, abortSignal
                    );
                } 
                // 3. Ollama 提供商
                else if (keyConfig.provider === 'ollama') {
                    text = await this.ollamaService.streamChat(
                        keyConfig.baseUrl || '', modelToUse, validHistory, 
                        newMessage, images, systemInstruction, generationConfig, keyConfig.key, onChunk, abortSignal
                    );
                } 
                // 4. 原生 Google Gemini 服务
                else {
                    text = await this.googleService.streamChat(
                        keyConfig.key, modelToUse, validHistory, 
                        newMessage, images, systemInstruction, generationConfig, onChunk, abortSignal
                    );
                }

                return { 
                    text, 
                    usedKeyIndex: this.getKeyDisplayIndex(keyConfig.id), 
                    provider: keyConfig.provider,
                    usedModel: modelToUse
                };

            } catch (error: any) {
                if (abortSignal?.aborted) throw new Error("Aborted by user");

                lastError = error;

                // 解析错误代码用于标记和显示
                let errorCode = 'Error';
                let statusCode = error.status || error.statusCode;

                if (!statusCode) {
                     const match = error.message?.match(/\b\d{3}\b/);
                     if (match) errorCode = match[0];
                     else if (error.message?.includes("Network")) errorCode = "Network";
                } else {
                    errorCode = statusCode.toString();
                }

                // 判断错误是否致命（是否需要禁用该 Key）
                let isFatal = [400, 401, 402, 403, 404].includes(statusCode);

                if (error.isSafety) {
                    throw new Error(this.getErrorMessage(error, lang));
                }

                if (this.onKeyError) {
                    this.onKeyError(keyConfig.id, errorCode, isFatal);
                }

                const localKey = this.keys.find(k => k.id === keyConfig.id);
                if (localKey) {
                    if (isFatal) localKey.isActive = false;
                    else {
                        localKey.isRateLimited = true;
                        localKey.lastUsed = Date.now();
                        this.keyUsageCount = 10000; 
                    }
                    localKey.lastErrorCode = errorCode;
                }

                if (this.keys.filter(k => k.isActive).length === 0) break; 

                attempts++;
                continue;
            }
        }

        if (lastError) throw new Error(this.getErrorMessage(lastError, lang));
        throw new Error(t('error.all_keys_failed', lang));
    }, abortSignal);
  }

  /**
   * Token 统计（加入队列处理）
   */
  public async countTokens(
      keyConfig: KeyConfig,
      history: Message[],
      newMessage: string,
      _ignoredSystemInstruction: string | undefined
  ): Promise<number> {
      return this.enqueueTask(async () => {
          if (keyConfig.provider !== 'google') return -1;
          return await this.googleService.countTokens(
              keyConfig.key, keyConfig.model || 'gemini-3-flash-preview', history, newMessage
          );
      });
  }
}

"use client";

import React, { useState, useEffect, useRef, Suspense, lazy } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { LLMService } from './services/llmService';
import { Message, Role, GeminiModel, AppSettings, KeyConfig, ChatSession, ModelProvider, APP_VERSION, ToastMessage, DialogConfig, ModelInfo } from './types';
import ChatInterface from './components/ChatInterface';
import Sidebar from './components/Sidebar';
import { Header } from './components/Header';
import ChatInput from './components/ChatInput';
import { t } from './utils/i18n';
import { ToastContainer } from './components/ui/Toast';
import { CustomDialog } from './components/ui/CustomDialog';
import { executeFilterScript } from './utils/scriptExecutor';

const SettingsModal = lazy(() => import('./components/SettingsModal'));
const SecurityLock = lazy(() => import('./components/SecurityLock'));
const MobileMenu = lazy(() => import('./components/MobileMenu'));

const DEFAULT_MODEL = 'gemini-3-flash-preview';
const STORAGE_KEYS_KEY = 'gemini_omnichat_keys_v4';
const STORAGE_SETTINGS_KEY = 'gemini_omnichat_settings_v8'; 
const STORAGE_SESSIONS_KEY = 'gemini_omnichat_sessions_v1';
const STORAGE_ACTIVE_SESSION_KEY = 'gemini_omnichat_active_session_v1';
const STORAGE_KNOWN_MODELS_KEY = 'gemini_omnichat_known_models_v1';

const ENV_KEY = process.env.API_KEY || '';

const DEFAULT_KNOWN_MODELS: ModelInfo[] = [
    { name: 'gemini-3-flash-preview', inputTokenLimit: 1048576, outputTokenLimit: 8192 },
    { name: 'gemini-3-pro-preview', inputTokenLimit: 2097152, outputTokenLimit: 8192 },
    { name: 'gemini-2.5-flash-thinking-preview-01-21', inputTokenLimit: 32768, outputTokenLimit: 8192 },
    { name: 'imagen-3.0-generate-001', displayName: 'Imagen 3 (Generate Images)', inputTokenLimit: 0, outputTokenLimit: 0 }
];

const App: React.FC = () => {
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [activeSessionId, setActiveSessionId] = useState<string>('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [inputImages, setInputImages] = useState<string[]>([]); 
  const [isLoading, setIsLoading] = useState(false);
  const [isSummarizing, setIsSummarizing] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isLocked, setIsLocked] = useState(false);
  const [apiKeys, setApiKeys] = useState<KeyConfig[]>([]);
  const [knownModels, setKnownModels] = useState<ModelInfo[]>(DEFAULT_KNOWN_MODELS);

  const [settings, setSettings] = useState<AppSettings>({
    defaultModel: DEFAULT_MODEL,
    defaultBaseUrl: 'https://api.openai.com/v1',
    systemPrompts: [],
    theme: 'light', 
    language: 'zh', 
    fontSize: 14,
    textWrapping: 'auto', 
    bubbleTransparency: 100, 
    showModelName: true, 
    kirbyThemeColor: false, 
    showTokenUsage: false, 
    showResponseTimer: false, 
    smoothAnimation: true, 
    avatarVisibility: 'always', 
    historyContextLimit: 0, 
    security: {
        enabled: false,
        questions: [],
        lastLogin: Date.now(),
        lockoutDurationSeconds: 86400 
    },
    generation: {
        temperature: 1.0,
        topP: 0.95,
        topK: 40,
        maxOutputTokens: 8192,
        stream: false, 
        thinkingBudget: 0, 
        stripThoughts: false 
    },
    scripts: {
        inputFilterEnabled: false,
        inputFilterCode: '',
        outputFilterEnabled: false,
        outputFilterCode: ''
    },
    enableKeyGrouping: false,
    keyGroups: []
  });

  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const [dialog, setDialog] = useState<DialogConfig>({
      isOpen: false,
      type: 'alert',
      title: '',
      onConfirm: () => {}
  });

  const [llmService, setLlmService] = useState<LLMService | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);
  const isProcessingRef = useRef(false);

  const addToast = (message: string, type: 'success' | 'error' | 'info' = 'info') => {
      setToasts(prev => [...prev, { id: uuidv4(), message, type }]);
  };

  const removeToast = (id: string) => {
      setToasts(prev => prev.filter(t => t.id !== id));
  };

  const showDialog = (config: Partial<DialogConfig> & { title: string, onConfirm: (value?: string) => void }) => {
      setDialog({
          isOpen: true,
          type: config.type || 'alert',
          title: config.title,
          message: config.message,
          inputValue: config.inputValue,
          inputPlaceholder: config.inputPlaceholder,
          onConfirm: config.onConfirm,
          onCancel: config.onCancel
      });
  };

  const closeDialog = () => {
      setDialog(prev => ({ ...prev, isOpen: false }));
  };

  /**
   * 初始化数据加载与迁移
   */
  useEffect(() => {
    const storedKeys = localStorage.getItem(STORAGE_KEYS_KEY);
    const oldKeysV3 = localStorage.getItem('gemini_omnichat_keys_v3');
    const oldSettingsStr = localStorage.getItem('gemini_omnichat_settings_v5');
    const oldSettings = oldSettingsStr ? JSON.parse(oldSettingsStr) : null;
    const globalModel = oldSettings?.model || DEFAULT_MODEL;
    const globalBaseUrl = oldSettings?.openAIBaseUrl || 'https://api.openai.com/v1';

    let initialKeys: KeyConfig[] = [];

    if (storedKeys) {
      initialKeys = JSON.parse(storedKeys);
    } else if (oldKeysV3) {
      const parsed = JSON.parse(oldKeysV3);
      initialKeys = parsed.map((k: any) => ({
          ...k,
          model: globalModel,
          baseUrl: k.provider === 'openai' ? globalBaseUrl : ''
      }));
    } else if (ENV_KEY) {
      initialKeys = ENV_KEY.split(',').map(k => k.trim()).filter(Boolean).map(k => ({
        id: uuidv4(),
        key: k,
        provider: 'google' as ModelProvider,
        isActive: true,
        usageLimit: 5, 
        isRateLimited: false,
        lastUsed: 0,
        model: DEFAULT_MODEL
      }));
    }
    setApiKeys(initialKeys);

    const storedSettings = localStorage.getItem(STORAGE_SETTINGS_KEY);
    let loadedSettings = settings;
    let loadedKnownModels = DEFAULT_KNOWN_MODELS;

    const storedKnownModels = localStorage.getItem(STORAGE_KNOWN_MODELS_KEY);
    if (storedKnownModels) {
        try {
            loadedKnownModels = JSON.parse(storedKnownModels);
        } catch (e) {}
    }

    if (storedSettings) {
      const parsedSettings = JSON.parse(storedSettings);
      if (parsedSettings.knownModels && !storedKnownModels) {
          loadedKnownModels = parsedSettings.knownModels;
      }
      if ('knownModels' in parsedSettings) delete parsedSettings.knownModels;
      loadedSettings = { ...settings, ...parsedSettings };
    } 
    setSettings(loadedSettings);
    setKnownModels(loadedKnownModels);

    const effectiveKeys = initialKeys.map(k => {
        if (!k.groupId) return k;
        const group = loadedSettings.keyGroups?.find(g => g.id === k.groupId);
        if (group && group.isActive === false) return { ...k, isActive: false };
        return k;
    });

    // 初始化 LLM 服务，包含自动禁用 Key 的逻辑
    setLlmService(new LLMService(effectiveKeys, (id, errorCode, isFatal = true) => {
        setApiKeys(prev => prev.map(k => {
            if (k.id !== id) return k;
            if (isFatal) return { ...k, isActive: false, lastErrorCode: errorCode };
            else return { ...k, isRateLimited: true, lastUsed: Date.now(), lastErrorCode: errorCode };
        }));
        if (isFatal) addToast(`${t('error.key_auto_disabled', loadedSettings.language)}${errorCode ? ` (${errorCode})` : ''}`, 'error');
    }));

    if (loadedSettings.security.enabled) {
        const lockoutThresholdMs = (loadedSettings.security.lockoutDurationSeconds || 86400) * 1000;
        if (Date.now() - (loadedSettings.security.lastLogin || 0) > lockoutThresholdMs) setIsLocked(true);
        else setSettings({ ...loadedSettings, security: { ...loadedSettings.security, lastLogin: Date.now() } });
    }

    const storedSessions = localStorage.getItem(STORAGE_SESSIONS_KEY);
    const storedActiveId = localStorage.getItem(STORAGE_ACTIVE_SESSION_KEY);

    if (storedSessions) {
      const parsedSessions = JSON.parse(storedSessions) as ChatSession[];
      if (parsedSessions.length > 0) {
        setSessions(parsedSessions);
        const targetId = (storedActiveId && parsedSessions.find(s => s.id === storedActiveId)) ? storedActiveId : parsedSessions[0].id;
        setActiveSessionId(targetId);
        setMessages(parsedSessions.find(s => s.id === targetId)?.messages || []);
      } else createNewSession();
    } else createNewSession();
  }, []);

  const createNewSession = () => {
    const newId = uuidv4();
    const newSession: ChatSession = {
      id: newId,
      title: t('msg.new_chat_title', settings.language),
      messages: [],
      createdAt: Date.now()
    };
    setSessions(prev => [newSession, ...prev]);
    setActiveSessionId(newId);
    setMessages([]);
  };

  /**
   * 监听密钥变动，同步更新服务层
   */
  useEffect(() => {
    const effectiveKeys = apiKeys.map(k => {
        if (!k.groupId) return k;
        const group = settings.keyGroups?.find(g => g.id === k.groupId);
        if (group && group.isActive === false) return { ...k, isActive: false };
        return k;
    });

    if (llmService) llmService.updateKeys(effectiveKeys);
    localStorage.setItem(STORAGE_KEYS_KEY, JSON.stringify(apiKeys));
  }, [apiKeys, llmService, settings.keyGroups]);

  useEffect(() => {
    localStorage.setItem(STORAGE_SETTINGS_KEY, JSON.stringify(settings));
    const root = document.documentElement;
    root.classList.remove('dark', 'theme-dark', 'theme-light', 'theme-twilight', 'theme-sky', 'theme-pink', 'theme-sunrise', 'theme-lime', 'theme-panda', 'theme-chocolate', 'theme-vscode-light', 'theme-vscode-dark');
    root.classList.add(`theme-${settings.theme}`);
    if (['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme)) root.classList.add('dark');
  }, [settings]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KNOWN_MODELS_KEY, JSON.stringify(knownModels));
  }, [knownModels]);

  useEffect(() => {
    if (!activeSessionId) return;
    setSessions(prev => {
      const idx = prev.findIndex(s => s.id === activeSessionId);
      if (idx === -1) return prev;
      const updated = [...prev];
      updated[idx] = { ...updated[idx], messages };
      return updated;
    });
  }, [messages, activeSessionId]);

  useEffect(() => {
    if (sessions.length > 0) localStorage.setItem(STORAGE_SESSIONS_KEY, JSON.stringify(sessions));
  }, [sessions]);

  useEffect(() => {
    if (activeSessionId) localStorage.setItem(STORAGE_ACTIVE_SESSION_KEY, activeSessionId);
  }, [activeSessionId]);

  /**
   * 核心聊天逻辑：触发机器人回复
   * 由于加入了队列功能，此处不再强制拦截并发，而是由 llmService 顺序执行。
   */
  const triggerBotResponse = async (historyBefore: Message[], userMessage: Message) => {
    if (!llmService) return;
    setIsLoading(true);

    if (abortControllerRef.current) abortControllerRef.current.abort();
    const controller = new AbortController();
    abortControllerRef.current = controller;

    const tempBotId = uuidv4();
    const botMessage: Message = {
      id: tempBotId,
      role: Role.MODEL,
      text: '',
      timestamp: Date.now()
    };

    setMessages([...historyBefore, userMessage, botMessage]);

    const startTime = Date.now();

    try {
      const systemInstruction = settings.systemPrompts.filter(p => p.isActive).map(p => p.content).join('\n\n');
      let historyForApi = historyBefore.filter(m => m.id !== userMessage.id);

      if (settings.generation.stripThoughts) {
        historyForApi = historyForApi.map(msg => {
            if (msg.role === Role.MODEL && msg.text.includes('<think>')) {
                 const cleanText = msg.text.replace(/<think>[\s\S]*?(?:<\/think>|$)/g, '').trim();
                 return { ...msg, text: cleanText };
            }
            return msg;
        });
      }

      let contextToSend = historyForApi;
      if (settings.historyContextLimit > 0 && historyForApi.length > settings.historyContextLimit) {
          contextToSend = historyForApi.slice(-settings.historyContextLimit);
      }

      // 关键调用：llmService 内部已实现排队
      const { text: fullText, usedKeyIndex, provider, usedModel } = await llmService.streamChatResponse(
        '', 
        contextToSend, 
        userMessage.text, 
        userMessage.images, 
        systemInstruction,
        settings.generation,
        (chunkText) => {
           let processedChunk = chunkText;
           if (settings.scripts?.outputFilterEnabled && settings.scripts.outputFilterCode) {
               processedChunk = executeFilterScript(settings.scripts.outputFilterCode, chunkText, { role: 'model', history: [...historyBefore, userMessage] });
           }
           setMessages(prev => prev.map(msg => msg.id === tempBotId ? { ...msg, text: processedChunk } : msg));
        },
        controller.signal,
        settings.language
      );

      const executionTime = Date.now() - startTime;
      let processedFinalText = fullText;

      if (settings.scripts?.outputFilterEnabled && settings.scripts.outputFilterCode) {
          processedFinalText = executeFilterScript(settings.scripts.outputFilterCode, fullText, { role: 'model', history: [...historyBefore, userMessage] });
      }

      setMessages(prev => 
        prev.map(msg => 
          msg.id === tempBotId ? { 
              ...msg, 
              text: processedFinalText, 
              keyIndex: usedKeyIndex, 
              provider: provider, 
              model: usedModel, 
              executionTime: executionTime
          } : msg
        )
      );
    } catch (error: any) {
      if (error.message !== "Aborted by user") {
         const errorMessage: Message = {
            id: uuidv4(),
            role: Role.MODEL,
            text: `${t('action.error', settings.language)}: ${error.message || t('error.unexpected_error', settings.language)}`,
            timestamp: Date.now(),
            isError: true,
            executionTime: Date.now() - startTime
         };
         setMessages(prev => prev.filter(m => m.id !== tempBotId).concat(errorMessage));
      }
    } finally {
      setIsLoading(false);
      abortControllerRef.current = null;
    }
  };

  const handleStopGeneration = () => {
      if (abortControllerRef.current) {
          abortControllerRef.current.abort();
          abortControllerRef.current = null;
          setIsLoading(false);
      }
  };

  const handleUnlock = () => {
      setIsLocked(false);
      const newSettings = { ...settings, security: { ...settings.security, lastLogin: Date.now() } };
      setSettings(newSettings);
      localStorage.setItem(STORAGE_SETTINGS_KEY, JSON.stringify(newSettings));
  };

  /**
   * 发送消息处理
   */
  const handleSendMessage = async () => {
    if (!llmService || isProcessingRef.current) return;
    if (!input.trim() && inputImages.length === 0) return;

    if (apiKeys.filter(k => k.isActive).length === 0) {
      setIsSettingsOpen(true);
      return;
    }

    isProcessingRef.current = true; 

    let processedInput = input.trim();
    if (settings.scripts?.inputFilterEnabled && settings.scripts.inputFilterCode) {
        processedInput = executeFilterScript(settings.scripts.inputFilterCode, processedInput, { role: 'user', history: messages });
    }

    const newMessage: Message = {
      id: uuidv4(),
      role: Role.USER,
      text: processedInput,
      images: inputImages.length > 0 ? [...inputImages] : undefined, 
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, newMessage]);
    setInput('');
    setInputImages([]); 

    try {
        await triggerBotResponse(messages, newMessage);
    } finally {
        isProcessingRef.current = false; 
    }
  };

  const handleGetTokenCount = async (currentInput: string): Promise<number> => {
      if (!llmService || apiKeys.length === 0) return 0;
      const activeKey = apiKeys.find(k => k.isActive);
      if (!activeKey) return 0;
      let contextToSend = messages;
      if (settings.generation.stripThoughts) {
        contextToSend = messages.map(msg => {
            if (msg.role === Role.MODEL && msg.text.includes('<think>')) {
                 const cleanText = msg.text.replace(/<think>[\s\S]*?(?:<\/think>|$)/g, '').trim();
                 return { ...msg, text: cleanText };
            }
            return msg;
        });
      }
      if (settings.historyContextLimit > 0 && contextToSend.length > settings.historyContextLimit) {
          contextToSend = contextToSend.slice(-settings.historyContextLimit);
      }
      const combinedSystemInstruction = settings.systemPrompts.filter(p => p.isActive).map(p => p.content).join('\n\n');
      return await llmService.countTokens(activeKey, contextToSend, currentInput, combinedSystemInstruction);
  };

  const handleEditMessage = (id: string, newText: string) => {
    setMessages(prev => prev.map(msg => msg.id === id ? { ...msg, text: newText } : msg));
  };

  const handleDeleteMessage = (id: string) => {
    setMessages(prev => prev.filter(msg => msg.id !== id));
  };

  const handleRegenerate = async (id: string) => {
    if (!llmService) return;
    const index = messages.findIndex(m => m.id === id);
    if (index === -1) return;
    const targetMsg = messages[index];

    if (targetMsg.role === Role.USER) {
       const historyBefore = messages.slice(0, index);
       await triggerBotResponse(historyBefore, targetMsg);
    } else {
      let userMsgIndex = index - 1;
      while (userMsgIndex >= 0 && messages[userMsgIndex].role !== Role.USER) userMsgIndex--;
      if (userMsgIndex === -1) {
        handleDeleteMessage(id);
        return;
      }
      const historyBefore = messages.slice(0, userMsgIndex);
      const userMsg = messages[userMsgIndex];
      await triggerBotResponse(historyBefore, userMsg);
    }
  };

  const handleNewChat = () => {
    handleStopGeneration();
    createNewSession();
    setIsMobileMenuOpen(false);
  };

  const handleClearChat = () => {
      if (messages.length === 0) return;
      showDialog({
          type: 'confirm',
          title: t('action.clear_chat', settings.language),
          message: t('msg.confirm_clear_chat', settings.language),
          onConfirm: () => {
              handleStopGeneration();
              setMessages([]);
              setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, messages: [] } : s));
          }
      });
  };

  const handleSelectSession = (sessionId: string) => {
    if (sessionId === activeSessionId) { setIsMobileMenuOpen(false); return; }
    handleStopGeneration();
    const session = sessions.find(s => s.id === sessionId);
    if (session) {
      setActiveSessionId(sessionId);
      setMessages(session.messages);
      setInput('');
      setIsMobileMenuOpen(false);
    }
  };

  const handleDeleteSession = (e: React.MouseEvent, sessionId: string) => {
    e.stopPropagation();
    const newSessions = sessions.filter(s => s.id !== sessionId);
    setSessions(newSessions);
    if (activeSessionId === sessionId) {
       handleStopGeneration();
       if (newSessions.length > 0) {
         setActiveSessionId(newSessions[0].id);
         setMessages(newSessions[0].messages);
       } else createNewSession();
    }
  };

  const handleSaveChat = () => {
    const activeSession = sessions.find(s => s.id === activeSessionId);
    const title = activeSession?.title || "Session";
    const safeTitle = title.replace(/[^a-z0-9\u4e00-\u9fa5]/gi, '_').substring(0, 50);
    const chatData = { title, date: new Date().toISOString(), messages };
    const blob = new Blob([JSON.stringify(chatData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `OmniChat-${safeTitle}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleLoadSession = (loadedMessages: any[], title?: string) => {
      handleStopGeneration();
      setMessages(loadedMessages);
      setInput('');
      if (title) setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: title } : s));
      addToast(t('success.chat_import', settings.language), 'success');
  };

  const handleSummarize = async () => {
    if (messages.length === 0 || !llmService) return;
    setIsSummarizing(true); 
    try {
        const historyText = messages.map(m => `${m.role === Role.USER ? 'User' : 'Model'}: ${m.text}`).join('\n');
        const prompt = t('msg.summarize_prompt', settings.language) + '\n\n' + historyText;
        const { text } = await llmService.streamChatResponse('', [], prompt, [], undefined, settings.generation, undefined, undefined, settings.language);
        const newTitle = text.trim().replace(/['"]/g, '').replace(/\.$/, '').replace(/\*\*/g, ''); 
        if (newTitle) {
            setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: newTitle } : s));
            addToast(t('action.ok', settings.language), 'success');
        }
    } catch (error: any) {
        addToast(t('msg.summarize_error', settings.language), 'error');
    } finally {
        setIsSummarizing(false);
    }
  };

  const handleRenameSession = () => {
    const currentSession = sessions.find(s => s.id === activeSessionId);
    const currentTitle = currentSession?.title || t('app.title', settings.language);
    showDialog({
        type: 'input',
        title: t('msg.rename_chat', settings.language),
        inputValue: currentTitle,
        onConfirm: (newTitle) => {
            if (newTitle && newTitle.trim()) setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: newTitle.trim() } : s));
        }
    });
  };

  const activeKeysCount = apiKeys.filter(k => k.isActive).length;
  const currentSessionTitle = sessions.find(s => s.id === activeSessionId)?.title || t('app.title', settings.language);

  if (isLocked) return (
    <div className={`${['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme) ? 'dark' : ''}`}>
        <Suspense fallback={<div className="flex h-screen items-center justify-center bg-gray-100 dark:bg-gray-950"></div>}>
            <SecurityLock config={settings.security} onUnlock={handleUnlock} lang={settings.language} theme={settings.theme} kirbyThemeColor={settings.kirbyThemeColor} />
        </Suspense>
    </div>
  );

  return (
    <div className={`flex h-screen font-sans ${['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme) ? 'dark' : ''}`}>
      <ToastContainer toasts={toasts} removeToast={removeToast} />
      <CustomDialog config={dialog} onClose={closeDialog} lang={settings.language} />

      <div className="flex w-full h-full bg-transparent text-gray-900 dark:text-gray-100 transition-colors duration-300">
        <Sidebar 
            sessions={sessions} activeSessionId={activeSessionId} activeKeysCount={activeKeysCount} 
            language={settings.language} theme={settings.theme} kirbyThemeColor={settings.kirbyThemeColor}
            onNewChat={handleNewChat} onSelectSession={handleSelectSession} onDeleteSession={handleDeleteSession}
            onOpenSettings={() => setIsSettingsOpen(true)}
        />

        <Suspense fallback={null}>
            <MobileMenu 
                isOpen={isMobileMenuOpen} sessions={sessions} activeSessionId={activeSessionId} language={settings.language}
                onClose={() => setIsMobileMenuOpen(false)} onNewChat={handleNewChat} onSelectSession={handleSelectSession}
                onDeleteSession={handleDeleteSession} onOpenSettings={() => setIsSettingsOpen(true)}
            />
        </Suspense>

        <main className="flex-1 flex flex-col relative h-full min-w-0">
          <Header 
             currentSessionTitle={currentSessionTitle} isSummarizing={isSummarizing} hasMessages={messages.length > 0}
             language={settings.language} onRename={handleRenameSession} onSummarize={handleSummarize}
             onOpenMobileMenu={() => setIsMobileMenuOpen(true)} onNewChat={handleNewChat} onClearChat={handleClearChat}
             onOpenSettings={() => setIsSettingsOpen(true)} onSaveChat={handleSaveChat} onLoadSession={handleLoadSession} onShowToast={addToast}
          />

          <ChatInterface 
              messages={messages} isLoading={isLoading} onEditMessage={handleEditMessage} onDeleteMessage={handleDeleteMessage} 
              onRegenerate={handleRegenerate} language={settings.language} fontSize={settings.fontSize} 
              textWrapping={settings.textWrapping} bubbleTransparency={settings.bubbleTransparency}
              showModelName={settings.showModelName} showResponseTimer={settings.showResponseTimer} theme={settings.theme}
              kirbyThemeColor={settings.kirbyThemeColor} onShowToast={addToast} smoothAnimation={settings.smoothAnimation}
              avatarVisibility={settings.avatarVisibility}
          />

          <div className="flex-shrink-0 z-20 bg-gradient-to-t from-white via-white/90 to-transparent dark:from-black dark:via-black/90 dark:to-transparent pt-4">
             <ChatInput 
                input={input} setInput={setInput} inputImages={inputImages} setInputImages={setInputImages}
                onSend={handleSendMessage} onStop={handleStopGeneration} isLoading={isLoading} isDisabled={activeKeysCount === 0}
                fontSize={settings.fontSize} language={settings.language} activeKeysCount={activeKeysCount} showTokenUsage={settings.showTokenUsage}
                history={messages} historyLimit={settings.historyContextLimit} onGetTokenCount={handleGetTokenCount} theme={settings.theme}
             />
             <div className="text-center text-[10px] text-gray-400 dark:text-gray-600 pb-1 select-none">
                {t('footer.ai_generated', settings.language)}{APP_VERSION}
             </div>
          </div>
        </main>

        <Suspense fallback={null}>
            <SettingsModal 
                isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} apiKeys={apiKeys} onUpdateKeys={setApiKeys} 
                settings={settings} onUpdateSettings={setSettings} llmService={llmService} onShowToast={addToast}
                onShowDialog={showDialog} knownModels={knownModels} onUpdateKnownModels={setKnownModels}
            />
        </Suspense>
      </div>
    </div>
  );
};

export default App;

"use client";

import React, { useState, useEffect, useRef, Suspense, lazy } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { LLMService } from './services/llmService';
import { Message, Role, GeminiModel, AppSettings, KeyConfig, ChatSession, ModelProvider, APP_VERSION, ToastMessage, DialogConfig, ModelInfo } from './types';
import ChatInterface from './components/ChatInterface';
import Sidebar from './components/Sidebar';
import { Header } from './components/Header';
import ChatInput from './components/ChatInput';
import { t } from './utils/i18n';
import { ToastContainer } from './components/ui/Toast';
import { CustomDialog } from './components/ui/CustomDialog';
import { executeFilterScript } from './utils/scriptExecutor';

const SettingsModal = lazy(() => import('./components/SettingsModal'));
const SecurityLock = lazy(() => import('./components/SecurityLock'));
const MobileMenu = lazy(() => import('./components/MobileMenu'));

const DEFAULT_MODEL = 'gemini-3-flash-preview';
const STORAGE_KEYS_KEY = 'gemini_omnichat_keys_v4';
const STORAGE_SETTINGS_KEY = 'gemini_omnichat_settings_v8'; 
const STORAGE_SESSIONS_KEY = 'gemini_omnichat_sessions_v1';
const STORAGE_ACTIVE_SESSION_KEY = 'gemini_omnichat_active_session_v1';
const STORAGE_KNOWN_MODELS_KEY = 'gemini_omnichat_known_models_v1';

const ENV_KEY = process.env.API_KEY || '';

const DEFAULT_KNOWN_MODELS: ModelInfo[] = [
    { name: 'gemini-3-flash-preview', inputTokenLimit: 1048576, outputTokenLimit: 8192 },
    { name: 'gemini-3-pro-preview', inputTokenLimit: 2097152, outputTokenLimit: 8192 },
    { name: 'gemini-2.5-flash-thinking-preview-01-21', inputTokenLimit: 32768, outputTokenLimit: 8192 },
    { name: 'imagen-3.0-generate-001', displayName: 'Imagen 3 (Generate Images)', inputTokenLimit: 0, outputTokenLimit: 0 }
];

const App: React.FC = () => {
  // --- 状态定义 ---
  const [sessions, setSessions] = useState<ChatSession[]>([]); // 会话列表
  const [activeSessionId, setActiveSessionId] = useState<string>(''); // 当前活动会话 ID
  const [messages, setMessages] = useState<Message[]>([]); // 当前会话的消息记录
  const [input, setInput] = useState(''); // 输入框文本
  const [inputImages, setInputImages] = useState<string[]>([]); // 待发送的图片
  const [isLoading, setIsLoading] = useState(false); // 是否正在生成回复
  const [isSummarizing, setIsSummarizing] = useState(false); // 是否正在总结标题
  const [isSettingsOpen, setIsSettingsOpen] = useState(false); // 设置弹窗开关
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false); // 移动端侧边栏开关
  const [isLocked, setIsLocked] = useState(false); // 隐私安全锁状态
  const [apiKeys, setApiKeys] = useState<KeyConfig[]>([]); // API 密钥池
  const [knownModels, setKnownModels] = useState<ModelInfo[]>(DEFAULT_KNOWN_MODELS); // 已知模型缓存

  // --- 应用配置 ---
  const [settings, setSettings] = useState<AppSettings>({
    defaultModel: DEFAULT_MODEL,
    defaultBaseUrl: 'https://api.openai.com/v1',
    systemPrompts: [],
    theme: 'light', 
    language: 'zh', 
    fontSize: 14,
    textWrapping: 'auto', 
    bubbleTransparency: 100, 
    showModelName: true, 
    kirbyThemeColor: false, 
    showTokenUsage: false, 
    showResponseTimer: false, 
    smoothAnimation: true, 
    avatarVisibility: 'always', 
    historyContextLimit: 0, 
    security: {
        enabled: false,
        questions: [],
        lastLogin: Date.now(),
        lockoutDurationSeconds: 86400 
    },
    generation: {
        temperature: 1.0,
        topP: 0.95,
        topK: 40,
        maxOutputTokens: 8192,
        stream: false, 
        thinkingBudget: 0, 
        stripThoughts: false 
    },
    scripts: {
        inputFilterEnabled: false,
        inputFilterCode: '',
        outputFilterEnabled: false,
        outputFilterCode: ''
    },
    enableKeyGrouping: false,
    keyGroups: []
  });

  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const [dialog, setDialog] = useState<DialogConfig>({
      isOpen: false,
      type: 'alert',
      title: '',
      onConfirm: () => {}
  });

  const [llmService, setLlmService] = useState<LLMService | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);
  const isProcessingRef = useRef(false);

  // --- 辅助工具函数 ---
  const addToast = (message: string, type: 'success' | 'error' | 'info' = 'info') => {
      setToasts(prev => [...prev, { id: uuidv4(), message, type }]);
  };

  const removeToast = (id: string) => {
      setToasts(prev => prev.filter(t => t.id !== id));
  };

  const showDialog = (config: Partial<DialogConfig> & { title: string, onConfirm: (value?: string) => void }) => {
      setDialog({
          isOpen: true,
          type: config.type || 'alert',
          title: config.title,
          message: config.message,
          inputValue: config.inputValue,
          inputPlaceholder: config.inputPlaceholder,
          onConfirm: config.onConfirm,
          onCancel: config.onCancel
      });
  };

  const closeDialog = () => {
      setDialog(prev => ({ ...prev, isOpen: false }));
  };

  /**
   * 节点 1: 挂载初始化
   * 从 LocalStorage 加载所有持久化数据，包括密钥、设置和会话历史。
   */
  useEffect(() => {
    const storedKeys = localStorage.getItem(STORAGE_KEYS_KEY);
    const oldKeysV3 = localStorage.getItem('gemini_omnichat_keys_v3');
    const oldSettingsStr = localStorage.getItem('gemini_omnichat_settings_v5');
    const oldSettings = oldSettingsStr ? JSON.parse(oldSettingsStr) : null;
    const globalModel = oldSettings?.model || DEFAULT_MODEL;
    const globalBaseUrl = oldSettings?.openAIBaseUrl || 'https://api.openai.com/v1';

    let initialKeys: KeyConfig[] = [];

    if (storedKeys) {
      initialKeys = JSON.parse(storedKeys);
    } else if (oldKeysV3) {
      const parsed = JSON.parse(oldKeysV3);
      initialKeys = parsed.map((k: any) => ({
          ...k,
          model: globalModel,
          baseUrl: k.provider === 'openai' ? globalBaseUrl : ''
      }));
    } else if (ENV_KEY) {
      initialKeys = ENV_KEY.split(',').map(k => k.trim()).filter(Boolean).map(k => ({
        id: uuidv4(),
        key: k,
        provider: 'google' as ModelProvider,
        isActive: true,
        usageLimit: 5, 
        isRateLimited: false,
        lastUsed: 0,
        model: DEFAULT_MODEL
      }));
    }
    setApiKeys(initialKeys);

    const storedSettings = localStorage.getItem(STORAGE_SETTINGS_KEY);
    let loadedSettings = settings;
    let loadedKnownModels = DEFAULT_KNOWN_MODELS;

    const storedKnownModels = localStorage.getItem(STORAGE_KNOWN_MODELS_KEY);
    if (storedKnownModels) {
        try {
            loadedKnownModels = JSON.parse(storedKnownModels);
        } catch (e) {}
    }

    if (storedSettings) {
      const parsedSettings = JSON.parse(storedSettings);
      if (parsedSettings.knownModels && !storedKnownModels) {
          loadedKnownModels = parsedSettings.knownModels;
      }
      if ('knownModels' in parsedSettings) delete parsedSettings.knownModels;
      loadedSettings = { ...settings, ...parsedSettings };
    } 
    setSettings(loadedSettings);
    setKnownModels(loadedKnownModels);

    const effectiveKeys = initialKeys.map(k => {
        if (!k.groupId) return k;
        const group = loadedSettings.keyGroups?.find(g => g.id === k.groupId);
        if (group && group.isActive === false) return { ...k, isActive: false };
        return k;
    });

    // 初始化核心 LLM 服务
    setLlmService(new LLMService(effectiveKeys, (id, errorCode, isFatal = true) => {
        setApiKeys(prev => prev.map(k => {
            if (k.id !== id) return k;
            if (isFatal) return { ...k, isActive: false, lastErrorCode: errorCode };
            else return { ...k, isRateLimited: true, lastUsed: Date.now(), lastErrorCode: errorCode };
        }));
        if (isFatal) addToast(`${t('error.key_auto_disabled', loadedSettings.language)}${errorCode ? ` (${errorCode})` : ''}`, 'error');
    }));

    // 安全锁检查
    if (loadedSettings.security.enabled) {
        const lockoutThresholdMs = (loadedSettings.security.lockoutDurationSeconds || 86400) * 1000;
        if (Date.now() - (loadedSettings.security.lastLogin || 0) > lockoutThresholdMs) setIsLocked(true);
        else setSettings({ ...loadedSettings, security: { ...loadedSettings.security, lastLogin: Date.now() } });
    }

    // 会话恢复
    const storedSessions = localStorage.getItem(STORAGE_SESSIONS_KEY);
    const storedActiveId = localStorage.getItem(STORAGE_ACTIVE_SESSION_KEY);

    if (storedSessions) {
      const parsedSessions = JSON.parse(storedSessions) as ChatSession[];
      if (parsedSessions.length > 0) {
        setSessions(parsedSessions);
        const targetId = (storedActiveId && parsedSessions.find(s => s.id === storedActiveId)) ? storedActiveId : parsedSessions[0].id;
        setActiveSessionId(targetId);
        setMessages(parsedSessions.find(s => s.id === targetId)?.messages || []);
      } else createNewSession();
    } else createNewSession();
  }, []);

  const createNewSession = () => {
    const newId = uuidv4();
    const newSession: ChatSession = {
      id: newId,
      title: t('msg.new_chat_title', settings.language),
      messages: [],
      createdAt: Date.now()
    };
    setSessions(prev => [newSession, ...prev]);
    setActiveSessionId(newId);
    setMessages([]);
  };

  /**
   * 节点 2: 数据同步
   * 监听状态变动并同步至服务层或持久化存储。
   */
  useEffect(() => {
    const effectiveKeys = apiKeys.map(k => {
        if (!k.groupId) return k;
        const group = settings.keyGroups?.find(g => g.id === k.groupId);
        if (group && group.isActive === false) return { ...k, isActive: false };
        return k;
    });

    if (llmService) llmService.updateKeys(effectiveKeys);
    localStorage.setItem(STORAGE_KEYS_KEY, JSON.stringify(apiKeys));
  }, [apiKeys, llmService, settings.keyGroups]);

  useEffect(() => {
    localStorage.setItem(STORAGE_SETTINGS_KEY, JSON.stringify(settings));
    const root = document.documentElement;
    root.classList.remove('dark', 'theme-dark', 'theme-light', 'theme-twilight', 'theme-sky', 'theme-pink', 'theme-sunrise', 'theme-lime', 'theme-panda', 'theme-chocolate', 'theme-vscode-light', 'theme-vscode-dark');
    root.classList.add(`theme-${settings.theme}`);
    if (['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme)) root.classList.add('dark');
  }, [settings]);

  useEffect(() => {
    if (!activeSessionId) return;
    setSessions(prev => {
      const idx = prev.findIndex(s => s.id === activeSessionId);
      if (idx === -1) return prev;
      const updated = [...prev];
      updated[idx] = { ...updated[idx], messages };
      return updated;
    });
  }, [messages, activeSessionId]);

  useEffect(() => {
    if (sessions.length > 0) localStorage.setItem(STORAGE_SESSIONS_KEY, JSON.stringify(sessions));
  }, [sessions]);

  useEffect(() => {
    if (activeSessionId) localStorage.setItem(STORAGE_ACTIVE_SESSION_KEY, activeSessionId);
  }, [activeSessionId]);

  /**
   * 节点 3: 消息处理逻辑
   * 处理流式响应并将其分片渲染至 UI。
   */
  const triggerBotResponse = async (historyBefore: Message[], userMessage: Message) => {
    if (!llmService) return;
    setIsLoading(true);

    if (abortControllerRef.current) abortControllerRef.current.abort();
    const controller = new AbortController();
    abortControllerRef.current = controller;

    const tempBotId = uuidv4();
    const botMessage: Message = {
      id: tempBotId,
      role: Role.MODEL,
      text: '',
      timestamp: Date.now()
    };

    setMessages([...historyBefore, userMessage, botMessage]);

    const startTime = Date.now();

    try {
      const systemInstruction = settings.systemPrompts.filter(p => p.isActive).map(p => p.content).join('\n\n');
      let historyForApi = historyBefore.filter(m => m.id !== userMessage.id);

      if (settings.generation.stripThoughts) {
        historyForApi = historyForApi.map(msg => {
            if (msg.role === Role.MODEL && msg.text.includes('<think>')) {
                 const cleanText = msg.text.replace(/<think>[\s\S]*?(?:<\/think>|$)/g, '').trim();
                 return { ...msg, text: cleanText };
            }
            return msg;
        });
      }

      let contextToSend = historyForApi;
      if (settings.historyContextLimit > 0 && historyForApi.length > settings.historyContextLimit) {
          contextToSend = historyForApi.slice(-settings.historyContextLimit);
      }

      // 执行流式调用
      const { text: fullText, usedKeyIndex, provider, usedModel } = await llmService.streamChatResponse(
        '', 
        contextToSend, 
        userMessage.text, 
        userMessage.images, 
        systemInstruction,
        settings.generation,
        (chunkText) => {
           let processedChunk = chunkText;
           if (settings.scripts?.outputFilterEnabled && settings.scripts.outputFilterCode) {
               processedChunk = executeFilterScript(settings.scripts.outputFilterCode, chunkText, { role: 'model', history: [...historyBefore, userMessage] });
           }
           setMessages(prev => prev.map(msg => msg.id === tempBotId ? { ...msg, text: processedChunk } : msg));
        },
        controller.signal,
        settings.language
      );

      const executionTime = Date.now() - startTime;
      let processedFinalText = fullText;

      if (settings.scripts?.outputFilterEnabled && settings.scripts.outputFilterCode) {
          processedFinalText = executeFilterScript(settings.scripts.outputFilterCode, fullText, { role: 'model', history: [...historyBefore, userMessage] });
      }

      setMessages(prev => 
        prev.map(msg => 
          msg.id === tempBotId ? { 
              ...msg, 
              text: processedFinalText, 
              keyIndex: usedKeyIndex, 
              provider: provider, 
              model: usedModel, 
              executionTime: executionTime
          } : msg
        )
      );
    } catch (error: any) {
      if (error.message !== "Aborted by user") {
         const errorMessage: Message = {
            id: uuidv4(),
            role: Role.MODEL,
            text: `${t('action.error', settings.language)}: ${error.message || t('error.unexpected_error', settings.language)}`,
            timestamp: Date.now(),
            isError: true,
            executionTime: Date.now() - startTime
         };
         setMessages(prev => prev.filter(m => m.id !== tempBotId).concat(errorMessage));
      }
    } finally {
      setIsLoading(false);
      abortControllerRef.current = null;
    }
  };

  const handleStopGeneration = () => {
      if (abortControllerRef.current) {
          abortControllerRef.current.abort();
          abortControllerRef.current = null;
          setIsLoading(false);
      }
  };

  const handleSendMessage = async () => {
    if (!llmService || isProcessingRef.current) return;
    if (!input.trim() && inputImages.length === 0) return;

    if (apiKeys.filter(k => k.isActive).length === 0) {
      setIsSettingsOpen(true);
      return;
    }

    isProcessingRef.current = true; 

    let processedInput = input.trim();
    if (settings.scripts?.inputFilterEnabled && settings.scripts.inputFilterCode) {
        processedInput = executeFilterScript(settings.scripts.inputFilterCode, processedInput, { role: 'user', history: messages });
    }

    const newMessage: Message = {
      id: uuidv4(),
      role: Role.USER,
      text: processedInput,
      images: inputImages.length > 0 ? [...inputImages] : undefined, 
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, newMessage]);
    setInput('');
    setInputImages([]); 

    try {
        await triggerBotResponse(messages, newMessage);
    } finally {
        isProcessingRef.current = false; 
    }
  };

  /**
   * 节点 4: 加载对话功能修复与增强
   * 将对话作为新会话导入，而不是覆盖当前会话，避免用户误操作。
   */
  const handleLoadSession = (loadedMessages: any[], title?: string) => {
      handleStopGeneration();

      // 生成新的会话对象
      const newId = uuidv4();
      const newSession: ChatSession = {
          id: newId,
          title: title || t('msg.new_chat_title', settings.language),
          messages: loadedMessages,
          createdAt: Date.now()
      };

      // 插入到会话列表最前端并立即切换
      setSessions(prev => [newSession, ...prev]);
      setActiveSessionId(newId);
      setMessages(loadedMessages);
      setInput('');

      addToast(t('msg.config_imported', settings.language), 'success');
  };

  const handleSaveChat = () => {
    const activeSession = sessions.find(s => s.id === activeSessionId);
    const title = activeSession?.title || "Session";
    const safeTitle = title.replace(/[^a-z0-9\u4e00-\u9fa5]/gi, '_').substring(0, 50);
    const chatData = { title, date: new Date().toISOString(), messages };
    const blob = new Blob([JSON.stringify(chatData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `OmniChat-${safeTitle}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleSelectSession = (sessionId: string) => {
    if (sessionId === activeSessionId) { setIsMobileMenuOpen(false); return; }
    handleStopGeneration();
    const session = sessions.find(s => s.id === sessionId);
    if (session) {
      setActiveSessionId(sessionId);
      setMessages(session.messages);
      setInput('');
      setIsMobileMenuOpen(false);
    }
  };

  const activeKeysCount = apiKeys.filter(k => k.isActive).length;
  const currentSessionTitle = sessions.find(s => s.id === activeSessionId)?.title || t('app.title', settings.language);

  if (isLocked) return (
    <div className={`${['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme) ? 'dark' : ''}`}>
        <Suspense fallback={<div className="flex h-screen items-center justify-center bg-gray-100 dark:bg-gray-950"></div>}>
            <SecurityLock config={settings.security} onUnlock={() => setIsLocked(false)} lang={settings.language} theme={settings.theme} kirbyThemeColor={settings.kirbyThemeColor} />
        </Suspense>
    </div>
  );

  return (
    <div className={`flex h-screen font-sans ${['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme) ? 'dark' : ''}`}>
      <ToastContainer toasts={toasts} removeToast={removeToast} />
      <CustomDialog config={dialog} onClose={closeDialog} lang={settings.language} />

      <div className="flex w-full h-full bg-transparent text-gray-900 dark:text-gray-100 transition-colors duration-300">
        <Sidebar 
            sessions={sessions} activeSessionId={activeSessionId} activeKeysCount={activeKeysCount} 
            language={settings.language} theme={settings.theme} kirbyThemeColor={settings.kirbyThemeColor}
            onNewChat={() => { handleStopGeneration(); createNewSession(); setIsMobileMenuOpen(false); }} 
            onSelectSession={handleSelectSession} 
            onDeleteSession={(e, id) => {
                e.stopPropagation();
                const newSessions = sessions.filter(s => s.id !== id);
                setSessions(newSessions);
                if (activeSessionId === id) {
                   handleStopGeneration();
                   if (newSessions.length > 0) {
                     setActiveSessionId(newSessions[0].id);
                     setMessages(newSessions[0].messages);
                   } else createNewSession();
                }
            }}
            onOpenSettings={() => setIsSettingsOpen(true)}
        />

        <Suspense fallback={null}>
            <MobileMenu 
                isOpen={isMobileMenuOpen} sessions={sessions} activeSessionId={activeSessionId} language={settings.language}
                onClose={() => setIsMobileMenuOpen(false)} onNewChat={() => { handleStopGeneration(); createNewSession(); setIsMobileMenuOpen(false); }} 
                onSelectSession={handleSelectSession}
                onDeleteSession={(e, id) => {
                    e.stopPropagation();
                    const newSessions = sessions.filter(s => s.id !== id);
                    setSessions(newSessions);
                    if (activeSessionId === id) {
                       handleStopGeneration();
                       if (newSessions.length > 0) {
                         setActiveSessionId(newSessions[0].id);
                         setMessages(newSessions[0].messages);
                       } else createNewSession();
                    }
                }} 
                onOpenSettings={() => setIsSettingsOpen(true)}
            />
        </Suspense>

        <main className="flex-1 flex flex-col relative h-full min-w-0">
          <Header 
             currentSessionTitle={currentSessionTitle} isSummarizing={isSummarizing} hasMessages={messages.length > 0}
             language={settings.language} onRename={() => {
                const currentSession = sessions.find(s => s.id === activeSessionId);
                showDialog({
                    type: 'input',
                    title: t('msg.rename_chat', settings.language),
                    inputValue: currentSession?.title || '',
                    onConfirm: (newTitle) => {
                        if (newTitle && newTitle.trim()) setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: newTitle.trim() } : s));
                    }
                });
             }} 
             onSummarize={async () => {
                if (messages.length === 0 || !llmService) return;
                setIsSummarizing(true); 
                try {
                    const historyText = messages.map(m => `${m.role === Role.USER ? 'User' : 'Model'}: ${m.text}`).join('\n');
                    const prompt = t('msg.summarize_prompt', settings.language) + '\n\n' + historyText;
                    const { text } = await llmService.streamChatResponse('', [], prompt, [], undefined, settings.generation, undefined, undefined, settings.language);
                    const newTitle = text.trim().replace(/['"]/g, '').replace(/\.$/, '').replace(/\*\*/g, ''); 
                    if (newTitle) {
                        setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: newTitle } : s));
                        addToast(t('action.ok', settings.language), 'success');
                    }
                } catch (e) {
                    addToast(t('msg.summarize_error', settings.language), 'error');
                } finally { setIsSummarizing(false); }
             }}
             onOpenMobileMenu={() => setIsMobileMenuOpen(true)} 
             onNewChat={() => { handleStopGeneration(); createNewSession(); }} 
             onClearChat={() => {
                if (messages.length === 0) return;
                showDialog({
                    type: 'confirm',
                    title: t('action.clear_chat', settings.language),
                    message: t('msg.confirm_clear_chat', settings.language),
                    onConfirm: () => {
                        handleStopGeneration();
                        setMessages([]);
                        setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, messages: [] } : s));
                    }
                });
             }}
             onOpenSettings={() => setIsSettingsOpen(true)} 
             onSaveChat={handleSaveChat} 
             onLoadSession={handleLoadSession} 
             onShowToast={addToast}
          />

          <ChatInterface 
              messages={messages} isLoading={isLoading} 
              onEditMessage={(id, newText) => setMessages(prev => prev.map(msg => msg.id === id ? { ...msg, text: newText } : msg))} 
              onDeleteMessage={(id) => setMessages(prev => prev.filter(msg => msg.id !== id))} 
              onRegenerate={async (id) => {
                if (!llmService) return;
                const index = messages.findIndex(m => m.id === id);
                if (index === -1) return;
                const targetMsg = messages[index];
                if (targetMsg.role === Role.USER) {
                   await triggerBotResponse(messages.slice(0, index), targetMsg);
                } else {
                  let userMsgIndex = index - 1;
                  while (userMsgIndex >= 0 && messages[userMsgIndex].role !== Role.USER) userMsgIndex--;
                  if (userMsgIndex !== -1) await triggerBotResponse(messages.slice(0, userMsgIndex), messages[userMsgIndex]);
                }
              }} 
              language={settings.language} fontSize={settings.fontSize} 
              textWrapping={settings.textWrapping} bubbleTransparency={settings.bubbleTransparency}
              showModelName={settings.showModelName} showResponseTimer={settings.showResponseTimer} theme={settings.theme}
              kirbyThemeColor={settings.kirbyThemeColor} onShowToast={addToast} smoothAnimation={settings.smoothAnimation}
              avatarVisibility={settings.avatarVisibility}
          />

          <div className="flex-shrink-0 z-20 bg-gradient-to-t from-white via-white/90 to-transparent dark:from-black dark:via-black/90 dark:to-transparent pt-4">
             <ChatInput 
                input={input} setInput={setInput} inputImages={inputImages} setInputImages={setInputImages}
                onSend={handleSendMessage} onStop={handleStopGeneration} isLoading={isLoading} isDisabled={activeKeysCount === 0}
                fontSize={settings.fontSize} language={settings.language} activeKeysCount={activeKeysCount} showTokenUsage={settings.showTokenUsage}
                history={messages} historyLimit={settings.historyContextLimit} 
                onGetTokenCount={async (currentInput) => {
                    if (!llmService || apiKeys.length === 0) return 0;
                    const activeKey = apiKeys.find(k => k.isActive);
                    if (!activeKey) return 0;
                    return await llmService.countTokens(activeKey, messages, currentInput, settings.systemPrompts.filter(p => p.isActive).map(p => p.content).join('\n\n'));
                }} 
                theme={settings.theme}
             />
             <div className="text-center text-[10px] text-gray-400 dark:text-gray-600 pb-1 select-none">
                {t('footer.ai_generated', settings.language)}{APP_VERSION}
             </div>
          </div>
        </main>

        <Suspense fallback={null}>
            <SettingsModal 
                isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} apiKeys={apiKeys} onUpdateKeys={setApiKeys} 
                settings={settings} onUpdateSettings={setSettings} llmService={llmService} onShowToast={addToast}
                onShowDialog={showDialog} knownModels={knownModels} onUpdateKnownModels={setKnownModels}
            />
        </Suspense>
      </div>
    </div>
  );
};

export default App;

import { Message, KeyConfig, GenerationConfig, ModelProvider, ModelInfo, Language } from "../types";
import { OpenAIService } from "./openaiService";
import { GoogleService } from "./googleService";
import { OllamaService } from "./ollamaService";
import { t } from "../utils/i18n";

/**
 * 队列任务接口定义
 */
interface RequestTask {
  execute: () => Promise<any>;
  resolve: (value: any) => void;
  reject: (reason?: any) => void;
  abortSignal?: AbortSignal;
}

/**
 * LLM 核心服务类：处理多提供商交互。
 * 包含：API 密钥轮询、负载均衡、请求队列处理。
 */
export class LLMService {
  private keys: KeyConfig[] = [];
  private keyIndex: number = 0; // 当前轮询到的 Key 索引
  private keyUsageCount: number = 0; // 当前 Key 已使用的次数

  // 队列管理状态：确保 API 请求按顺序处理，避免高并发冲突
  private requestQueue: RequestTask[] = [];
  private isProcessingQueue: boolean = false;

  private openAIService: OpenAIService;
  private googleService: GoogleService;
  private ollamaService: OllamaService;
  private onKeyError?: (id: string, errorCode?: string, isFatal?: boolean) => void;

  constructor(initialKeys: KeyConfig[], onKeyError?: (id: string, errorCode?: string, isFatal?: boolean) => void) {
    this.updateKeys(initialKeys);
    this.openAIService = new OpenAIService();
    this.googleService = new GoogleService();
    this.ollamaService = new OllamaService();
    this.onKeyError = onKeyError;
  }

  /**
   * 更新 API 密钥池
   */
  public updateKeys(newKeys: KeyConfig[]) {
    this.keys = newKeys;
    // 索引越界安全检查
    if (this.keyIndex >= this.keys.length) {
        this.keyIndex = 0;
        this.keyUsageCount = 0;
    }
  }

  /**
   * 将任务推入队列并触发处理逻辑
   */
  private async enqueueTask<T>(execute: () => Promise<T>, abortSignal?: AbortSignal): Promise<T> {
    return new Promise((resolve, reject) => {
      if (abortSignal?.aborted) {
        return reject(new Error("Aborted by user"));
      }

      this.requestQueue.push({
        execute,
        resolve,
        reject,
        abortSignal
      });

      this.processQueue();
    });
  }

  /**
   * 顺序处理队列中的任务 (FIFO)
   */
  private async processQueue() {
    if (this.isProcessingQueue || this.requestQueue.length === 0) return;

    this.isProcessingQueue = true;

    while (this.requestQueue.length > 0) {
      const task = this.requestQueue.shift();
      if (!task) continue;

      if (task.abortSignal?.aborted) {
        task.reject(new Error("Aborted by user"));
        continue;
      }

      try {
        const result = await task.execute();
        task.resolve(result);
      } catch (error) {
        task.reject(error);
      }
    }

    this.isProcessingQueue = false;
  }

  /**
   * 获取模型列表
   */
  public async listModels(keyConfig: KeyConfig): Promise<ModelInfo[]> {
    return this.enqueueTask(async () => {
      if (keyConfig.provider === 'openai') {
          if (!keyConfig.baseUrl) throw new Error("Base URL is required for OpenAI provider");
          return await this.openAIService.listModels(keyConfig.key, keyConfig.baseUrl);
      } else if (keyConfig.provider === 'ollama') {
          return await this.ollamaService.listModels(keyConfig.baseUrl || '', keyConfig.key);
      } else {
          return await this.googleService.listModels(keyConfig.key);
      }
    });
  }

  /**
   * 测试连接
   */
  public async testConnection(keyConfig: KeyConfig): Promise<boolean> {
    return this.enqueueTask(async () => {
      const modelToUse = keyConfig.model || (keyConfig.provider === 'openai' ? 'gpt-3.5-turbo' : 'gemini-2.5-flash');
      try {
          if (keyConfig.provider === 'openai') {
              if (!keyConfig.baseUrl) return false;
              return await this.openAIService.testChat(keyConfig.key, keyConfig.baseUrl, modelToUse);
          } else if (keyConfig.provider === 'ollama') {
              return await this.ollamaService.testConnection(keyConfig.baseUrl || '', keyConfig.key);
          } else {
              return await this.googleService.testConnection(keyConfig.key, modelToUse);
          }
      } catch (e) {
          return false;
      }
    });
  }

  /**
   * 核心算法：轮询策略
   * 寻找下一个可用的 API 密钥，考虑：活跃状态、速率限制冷却时间、单个 Key 的轮询配额。
   */
  private getNextAvailableKey(lang: Language): KeyConfig {
    const activeKeys = this.keys.filter(k => k.isActive);

    if (activeKeys.length === 0) {
      throw new Error(t('error.no_active_keys', lang));
    }

    const attempts = activeKeys.length;
    let selectedKey: KeyConfig | null = null;
    let selectedIndex = -1;

    for (let i = 0; i < attempts; i++) {
        const idx = (this.keyIndex + i) % activeKeys.length;
        const candidate = activeKeys[idx];

        // 检查冷却时间：如果被 429 限制，进入 1 分钟冷却期
        if (candidate.isRateLimited && Date.now() - candidate.lastUsed < 60000) {
            continue; 
        }

        // 检查轮询配额：如果当前 Key 还没用够设定的次数，继续用它
        if (i === 0 && this.keyUsageCount < (candidate.usageLimit || 1)) {
             selectedKey = candidate;
             selectedIndex = idx;
             break;
        }

        // 切换到下一个 Key
        if (i > 0) {
            selectedKey = candidate;
            selectedIndex = idx;
            break;
        }
    }

    // 如果所有 Key 都因为某种原因被跳过，强制选择当前索引的下一个
    if (!selectedKey) {
        selectedIndex = (this.keyIndex + 1) % activeKeys.length;
        selectedKey = activeKeys[selectedIndex];
    }

    // 如果发生了索引切换，重置单密钥使用计数
    if (this.keyIndex !== selectedIndex) {
        this.keyIndex = selectedIndex;
        this.keyUsageCount = 0;
    }

    this.keyUsageCount++;
    return selectedKey;
  }

  private getKeyDisplayIndex(id: string): number {
      return this.keys.findIndex(k => k.id === id) + 1;
  }

  /**
   * 错误分级处理逻辑
   * 将 API 返回的原始错误转化为用户可读的本地化语言。
   */
  private getErrorMessage(error: any, lang: Language): string {
      const status = error.status || error.statusCode;
      const msg = error.message?.toLowerCase() || '';

      if (status === 401 || msg.includes('401') || msg.includes('invalid api key')) return t('error.invalid_api_key', lang);
      if (status === 402 || msg.includes('402') || msg.includes('billing')) return t('error.billing_required', lang);
      if (status === 403 || msg.includes('403') || msg.includes('permission denied')) return t('error.permission_denied', lang);
      if (status === 404 || msg.includes('404') || msg.includes('not found')) return t('error.model_not_found', lang);
      if (status === 429 || msg.includes('429') || msg.includes('quota') || msg.includes('rate limit')) return t('error.quota_exceeded', lang);
      if (status === 400 || msg.includes('400')) {
          if (msg.includes('safety') || error.isSafety) return t('error.safety_block', lang);
          if (msg.includes('context')) return t('error.context_length_exceeded', lang);
          return t('error.bad_request', lang);
      }
      if (status === 500 || status === 502 || status === 503 || msg.includes('500')) return t('error.server_error', lang);
      if (status === 0 || msg.includes('network') || msg.includes('fetch')) return t('error.network_issue', lang);

      return error.message || t('error.unexpected_error', lang);
  }

  /**
   * 节点 5: 核心重试与分发逻辑
   * 在发生非致命错误（如速率限制）时自动切换密钥并重试。
   */
  public async streamChatResponse(
    _ignoredGlobalModelId: string, 
    history: Message[],
    newMessage: string,
    images: string[] | undefined,
    systemInstruction: string | undefined,
    generationConfig: GenerationConfig,
    onChunk?: (text: string) => void,
    abortSignal?: AbortSignal,
    lang: Language = 'en'
  ): Promise<{ text: string, usedKeyIndex: number, provider: ModelProvider, usedModel: string }> {

    return this.enqueueTask(async () => {
        const activeKeysCount = this.keys.filter(k => k.isActive).length;
        // 最大重试次数为活跃密钥数的 2 倍
        const maxRetries = Math.max(activeKeysCount * 2, 2); 
        let attempts = 0;
        const validHistory = history.filter(msg => (msg.text && msg.text.trim().length > 0) || (msg.images && msg.images.length > 0));

        let lastError: any = null;

        while (attempts < maxRetries) {
            let keyConfig: KeyConfig;
            try {
                keyConfig = this.getNextAvailableKey(lang);
            } catch (e: any) {
                throw e;
            }

            const modelToUse = keyConfig.model || _ignoredGlobalModelId || 'gemini-3-flash-preview';

            try {
                let text = "";

                // 根据提供商分发请求
                if (keyConfig.provider === 'google' && modelToUse.toLowerCase().includes('imagen')) {
                     text = await this.googleService.generateImage(keyConfig.key, modelToUse, newMessage);
                } 
                else if (keyConfig.provider === 'openai') {
                    if (!keyConfig.baseUrl) throw new Error(t('error.base_url_required', lang));
                    text = await this.openAIService.streamChat(
                        keyConfig.key, keyConfig.baseUrl, modelToUse, validHistory, 
                        newMessage, images, systemInstruction, generationConfig, onChunk, abortSignal
                    );
                } 
                else if (keyConfig.provider === 'ollama') {
                    text = await this.ollamaService.streamChat(
                        keyConfig.baseUrl || '', modelToUse, validHistory, 
                        newMessage, images, systemInstruction, generationConfig, keyConfig.key, onChunk, abortSignal
                    );
                } 
                else {
                    text = await this.googleService.streamChat(
                        keyConfig.key, modelToUse, validHistory, 
                        newMessage, images, systemInstruction, generationConfig, onChunk, abortSignal
                    );
                }

                return { 
                    text, 
                    usedKeyIndex: this.getKeyDisplayIndex(keyConfig.id), 
                    provider: keyConfig.provider,
                    usedModel: modelToUse
                };

            } catch (error: any) {
                if (abortSignal?.aborted) throw new Error("Aborted by user");

                lastError = error;
                let errorCode = 'Error';
                let statusCode = error.status || error.statusCode;

                if (!statusCode) {
                     const match = error.message?.match(/\b\d{3}\b/);
                     if (match) errorCode = match[0];
                     else if (error.message?.includes("Network")) errorCode = "Network";
                } else {
                    errorCode = statusCode.toString();
                }

                // 判断是否是致命错误：身份验证失败、计费问题、位置不支持等需要禁用密钥
                let isFatal = [401, 402, 403, 404].includes(statusCode);

                // 安全审核拦截不属于密钥问题，直接抛出给用户
                if (error.isSafety) {
                    throw new Error(this.getErrorMessage(error, lang));
                }

                if (this.onKeyError) {
                    this.onKeyError(keyConfig.id, errorCode, isFatal);
                }

                const localKey = this.keys.find(k => k.id === keyConfig.id);
                if (localKey) {
                    if (isFatal) localKey.isActive = false;
                    else {
                        // 速率限制错误：进入冷却
                        localKey.isRateLimited = true;
                        localKey.lastUsed = Date.now();
                        // 强制轮询配额用满，以便下次重试使用新 Key
                        this.keyUsageCount = 10000; 
                    }
                    localKey.lastErrorCode = errorCode;
                }

                if (this.keys.filter(k => k.isActive).length === 0) break; 

                attempts++;
                continue;
            }
        }

        if (lastError) throw new Error(this.getErrorMessage(lastError, lang));
        throw new Error(t('error.all_keys_failed', lang));
    }, abortSignal);
  }

  /**
   * Token 统计
   */
  public async countTokens(
      keyConfig: KeyConfig,
      history: Message[],
      newMessage: string,
      _ignoredSystemInstruction: string | undefined
  ): Promise<number> {
      return this.enqueueTask(async () => {
          if (keyConfig.provider !== 'google') return -1;
          return await this.googleService.countTokens(
              keyConfig.key, keyConfig.model || 'gemini-3-flash-preview', history, newMessage
          );
      });
  }
}

"use client";

import React, { useRef, useState, useEffect } from 'react';
import { Menu, Settings, Loader2, Sparkles, Download, Upload, Eraser, MoreHorizontal, ChevronUp } from 'lucide-react';
import { Language } from '../types';
import { t } from '../utils/i18n';

interface HeaderProps {
  currentSessionTitle: string;
  isSummarizing: boolean;
  hasMessages: boolean;
  language: Language;
  onRename: () => void;
  onSummarize: () => void;
  onOpenMobileMenu: () => void;
  onNewChat: () => void;
  onClearChat: () => void;
  onOpenSettings: () => void;
  onSaveChat: () => void;
  onLoadSession: (messages: any[], title?: string) => void;
  onShowToast: (message: string, type: 'success' | 'error' | 'info') => void;
}

export const Header: React.FC<HeaderProps> = ({
  currentSessionTitle,
  isSummarizing,
  hasMessages,
  language,
  onRename,
  onSummarize,
  onOpenMobileMenu,
  onNewChat,
  onClearChat,
  onOpenSettings,
  onSaveChat,
  onLoadSession,
  onShowToast
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isActionsOpen, setIsActionsOpen] = useState(false);
  const menuRef = useRef<HTMLDivElement>(null);

  /**
   * 节点 1: 外部点击监听
   * 用于自动关闭展开的操作菜单
   */
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && menuRef.current.contains(event.target as Node)) return;
      setIsActionsOpen(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  /**
   * 节点 2: 触发文件选择器
   * 修复点：通过 ref 稳定触发隐藏的 input 元素
   */
  const handleLoadTrigger = () => {
    if (fileInputRef.current) {
        fileInputRef.current.click();
    }
    setIsActionsOpen(false);
  };

  /**
   * 节点 3: 文件读取逻辑
   * 解析 JSON 并验证消息格式，成功后回调父组件进行会话切换
   */
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const content = event.target?.result as string;
        const parsed = JSON.parse(content);

        // 关键节点：验证对话文件是否包含有效的消息数组
        if (parsed && parsed.messages && Array.isArray(parsed.messages)) {
          onLoadSession(parsed.messages, parsed.title);
        } else {
          onShowToast(t('error.invalid_chat_file', language), 'error');
        }
      } catch (err) {
        onShowToast(t('error.load_file', language), 'error');
      }

      // 清空 input 值，允许重复上传同一个文件触发 onChange
      if (fileInputRef.current) {
          fileInputRef.current.value = '';
      }
    };
    reader.readAsText(file);
  };

  /**
   * 子组件：操作菜单按钮组
   * 注意：不要在这里定义包含 ref 的 input 元素，应移至外层
   */
  const ActionButtons = () => (
    <div className="relative flex items-center" ref={menuRef}>
      <button
        onClick={() => setIsActionsOpen(!isActionsOpen)}
        className={`p-2 rounded-full transition-all duration-300 z-20 ${isActionsOpen ? 'bg-primary-100 dark:bg-primary-900/30 text-primary-600' : 'bg-transparent text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-800'}`}
        title={t('settings.manage', language)}
      >
        {isActionsOpen ? <ChevronUp className="w-5 h-5" /> : <MoreHorizontal className="w-5 h-5" />}
      </button>

      <div 
        className={`absolute top-full right-0 mt-2 flex flex-col gap-1.5 p-1.5 bg-white/95 dark:bg-gray-900/95 backdrop-blur-xl border border-gray-200 dark:border-gray-800 rounded-2xl shadow-2xl transition-all duration-300 origin-top-right z-30 ${
          isActionsOpen 
          ? 'opacity-100 translate-y-0 scale-100' 
          : 'opacity-0 -translate-y-4 scale-95 pointer-events-none'
        }`}
      >
        <button
          onClick={() => { onSummarize(); setIsActionsOpen(false); }}
          disabled={isSummarizing || !hasMessages}
          className="flex items-center gap-3 px-4 py-2.5 rounded-xl text-sm font-medium text-gray-700 dark:text-gray-300 hover:bg-primary-50 dark:hover:bg-primary-900/20 hover:text-primary-600 dark:hover:text-primary-400 transition-colors whitespace-nowrap disabled:opacity-30"
        >
          {isSummarizing ? <Loader2 className="w-4 h-4 animate-spin"/> : <Sparkles className="w-4 h-4" />}
          <span>{t('action.summarize', language)}</span>
        </button>

        <button
          onClick={() => { onOpenSettings(); setIsActionsOpen(false); }}
          className="md:hidden flex items-center gap-3 px-4 py-2.5 rounded-xl text-sm font-medium text-gray-700 dark:text-gray-300 hover:bg-primary-50 dark:hover:bg-primary-900/20 hover:text-primary-600 dark:hover:text-primary-400 transition-colors whitespace-nowrap"
        >
          <Settings className="w-4 h-4" />
          <span>{t('action.settings', language)}</span>
        </button>

        <button
            onClick={() => { onClearChat(); setIsActionsOpen(false); }}
            disabled={!hasMessages}
            className="flex items-center gap-3 px-4 py-2.5 rounded-xl text-sm font-medium text-gray-700 dark:text-gray-300 hover:bg-red-50 dark:hover:bg-red-900/20 hover:text-red-600 dark:hover:text-red-400 transition-colors whitespace-nowrap disabled:opacity-30"
        >
            <Eraser className="w-4 h-4" />
            <span>{t('action.clear_chat', language)}</span>
        </button>

        <button 
          onClick={() => { onSaveChat(); setIsActionsOpen(false); }} 
          disabled={!hasMessages}
          className="flex items-center gap-3 px-4 py-2.5 rounded-xl text-sm font-medium text-gray-700 dark:text-gray-300 hover:bg-primary-50 dark:hover:bg-primary-900/20 hover:text-primary-600 dark:hover:text-primary-400 transition-colors whitespace-nowrap disabled:opacity-30"
        >
          <Download className="w-4 h-4" />
          <span>{t('action.save', language)}</span>
        </button>

        <button 
          onClick={handleLoadTrigger} 
          className="flex items-center gap-3 px-4 py-2.5 rounded-xl text-sm font-medium text-gray-700 dark:text-gray-300 hover:bg-primary-50 dark:hover:bg-primary-900/20 hover:text-primary-600 dark:hover:text-primary-400 transition-colors whitespace-nowrap"
        >
          <Upload className="w-4 h-4" />
          <span>{t('action.load', language)}</span>
        </button>
      </div>
    </div>
  );

  return (
    <>
      {/* 稳定节点：将隐藏的 input 放置在 Header 根部，确保 ref 不受子组件重绘影响 */}
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileChange} 
        accept=".json" 
        className="hidden" 
        aria-label={t('action.select_chat_file', language)} 
      />

      {/* Desktop Header */}
      <header className="hidden md:flex items-center justify-between px-6 py-4 border-b border-gray-200 dark:border-gray-800 bg-white/30 dark:bg-black/30 backdrop-blur-sm z-30 transition-colors">
        <div className="flex items-center gap-3 overflow-hidden">
          <h1 
            className="font-bold text-lg text-gray-800 dark:text-white truncate max-w-xl cursor-pointer hover:underline decoration-dashed underline-offset-4" 
            onClick={onRename} 
            title={t('action.rename_manually', language)}
            aria-label={t('action.rename_current_chat', language)}
          >
            {currentSessionTitle}
          </h1>
        </div>

        <div className="flex items-center gap-2">
            <ActionButtons />
        </div>
      </header>

      {/* Mobile Header */}
      <header className="md:hidden flex items-center justify-between p-3 border-b border-gray-200 dark:border-gray-800 bg-white/80 dark:bg-black/40 backdrop-blur-md sticky top-0 z-30">
        <div className="flex items-center gap-2 overflow-hidden flex-1">
          <button 
            onClick={onOpenMobileMenu} 
            className="p-1 flex-shrink-0 text-gray-700 dark:text-gray-200"
            aria-label={t('action.open_mobile_navigation', language)}
          >
            <Menu className="w-6 h-6" />
          </button>
          <div className="flex items-center gap-1 overflow-hidden min-w-0">
            <span 
                className="font-bold text-lg dark:text-white truncate max-w-[120px] cursor-pointer hover:underline decoration-dashed underline-offset-4"
                onClick={onRename}
                title={t('action.rename_manually', language)}
                aria-label={t('action.rename_current_chat', language)}
            >
                {currentSessionTitle}
            </span>
          </div>
        </div>
        <div className="flex gap-0.5 flex-shrink-0 ml-1">
          <ActionButtons />
        </div>
      </header>
    </>
  );
};

"use client";

import React, { useState, useEffect, useRef, Suspense, lazy } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { LLMService } from './services/llmService';
import { Message, Role, GeminiModel, AppSettings, KeyConfig, ChatSession, ModelProvider, APP_VERSION, ToastMessage, DialogConfig, ModelInfo } from './types';
import ChatInterface from './components/ChatInterface';
import Sidebar from './components/Sidebar';
import { Header } from './components/Header';
import ChatInput from './components/ChatInput';
import { t } from './utils/i18n';
import { ToastContainer } from './components/ui/Toast';
import { CustomDialog } from './components/ui/CustomDialog';
import { executeFilterScript } from './utils/scriptExecutor';

const SettingsModal = lazy(() => import('./components/SettingsModal'));
const SecurityLock = lazy(() => import('./components/SecurityLock'));
const MobileMenu = lazy(() => import('./components/MobileMenu'));

const DEFAULT_MODEL = 'gemini-3-flash-preview';
const STORAGE_KEYS_KEY = 'gemini_omnichat_keys_v4';
const STORAGE_SETTINGS_KEY = 'gemini_omnichat_settings_v8'; 
const STORAGE_SESSIONS_KEY = 'gemini_omnichat_sessions_v1';
const STORAGE_ACTIVE_SESSION_KEY = 'gemini_omnichat_active_session_v1';
const STORAGE_KNOWN_MODELS_KEY = 'gemini_omnichat_known_models_v1';

const ENV_KEY = process.env.API_KEY || '';

const DEFAULT_KNOWN_MODELS: ModelInfo[] = [
    { name: 'gemini-3-flash-preview', inputTokenLimit: 1048576, outputTokenLimit: 8192 },
    { name: 'gemini-3-pro-preview', inputTokenLimit: 2097152, outputTokenLimit: 8192 },
    { name: 'gemini-2.5-flash-thinking-preview-01-21', inputTokenLimit: 32768, outputTokenLimit: 8192 },
    { name: 'imagen-3.0-generate-001', displayName: 'Imagen 3 (Generate Images)', inputTokenLimit: 0, outputTokenLimit: 0 }
];

const App: React.FC = () => {
  // --- 状态定义 ---
  const [sessions, setSessions] = useState<ChatSession[]>([]); // 会话列表
  const [activeSessionId, setActiveSessionId] = useState<string>(''); // 当前活动会话 ID
  const [messages, setMessages] = useState<Message[]>([]); // 当前会话的消息记录
  const [input, setInput] = useState(''); // 输入框文本
  const [inputImages, setInputImages] = useState<string[]>([]); // 待发送的图片
  const [isLoading, setIsLoading] = useState(false); // 是否正在生成回复
  const [isSummarizing, setIsSummarizing] = useState(false); // 是否正在总结标题
  const [isSettingsOpen, setIsSettingsOpen] = useState(false); // 设置弹窗开关
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false); // 移动端侧边栏开关
  const [isLocked, setIsLocked] = useState(false); // 隐私安全锁状态
  const [apiKeys, setApiKeys] = useState<KeyConfig[]>([]); // API 密钥池
  const [knownModels, setKnownModels] = useState<ModelInfo[]>(DEFAULT_KNOWN_MODELS); // 已知模型缓存

  // --- 应用配置 ---
  const [settings, setSettings] = useState<AppSettings>({
    defaultModel: DEFAULT_MODEL,
    defaultBaseUrl: 'https://api.openai.com/v1',
    systemPrompts: [],
    theme: 'light', 
    language: 'zh', 
    fontSize: 14,
    textWrapping: 'auto', 
    bubbleTransparency: 100, 
    showModelName: true, 
    kirbyThemeColor: false, 
    showTokenUsage: false, 
    showResponseTimer: false, 
    smoothAnimation: true, 
    avatarVisibility: 'always', 
    historyContextLimit: 0, 
    security: {
        enabled: false,
        questions: [],
        lastLogin: Date.now(),
        lockoutDurationSeconds: 86400 
    },
    generation: {
        temperature: 1.0,
        topP: 0.95,
        topK: 40,
        maxOutputTokens: 8192,
        stream: false, 
        thinkingBudget: 0, 
        stripThoughts: false 
    },
    scripts: {
        inputFilterEnabled: false,
        inputFilterCode: '',
        outputFilterEnabled: false,
        outputFilterCode: ''
    },
    enableKeyGrouping: false,
    keyGroups: []
  });

  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const [dialog, setDialog] = useState<DialogConfig>({
      isOpen: false,
      type: 'alert',
      title: '',
      onConfirm: () => {}
  });

  const [llmService, setLlmService] = useState<LLMService | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);
  const isProcessingRef = useRef(false);

  // --- 辅助工具函数 ---
  const addToast = (message: string, type: 'success' | 'error' | 'info' = 'info') => {
      setToasts(prev => [...prev, { id: uuidv4(), message, type }]);
  };

  const removeToast = (id: string) => {
      setToasts(prev => prev.filter(t => t.id !== id));
  };

  const showDialog = (config: Partial<DialogConfig> & { title: string, onConfirm: (value?: string) => void }) => {
      setDialog({
          isOpen: true,
          type: config.type || 'alert',
          title: config.title,
          message: config.message,
          inputValue: config.inputValue,
          inputPlaceholder: config.inputPlaceholder,
          onConfirm: config.onConfirm,
          onCancel: config.onCancel
      });
  };

  const closeDialog = () => {
      setDialog(prev => ({ ...prev, isOpen: false }));
  };

  /**
   * 节点 1: 挂载初始化
   * 从 LocalStorage 加载所有持久化数据，包括密钥、设置和会话历史。
   */
  useEffect(() => {
    const storedKeys = localStorage.getItem(STORAGE_KEYS_KEY);
    const oldKeysV3 = localStorage.getItem('gemini_omnichat_keys_v3');
    const oldSettingsStr = localStorage.getItem('gemini_omnichat_settings_v5');
    const oldSettings = oldSettingsStr ? JSON.parse(oldSettingsStr) : null;
    const globalModel = oldSettings?.model || DEFAULT_MODEL;
    const globalBaseUrl = oldSettings?.openAIBaseUrl || 'https://api.openai.com/v1';

    let initialKeys: KeyConfig[] = [];

    if (storedKeys) {
      initialKeys = JSON.parse(storedKeys);
    } else if (oldKeysV3) {
      const parsed = JSON.parse(oldKeysV3);
      initialKeys = parsed.map((k: any) => ({
          ...k,
          model: globalModel,
          baseUrl: k.provider === 'openai' ? globalBaseUrl : ''
      }));
    } else if (ENV_KEY) {
      initialKeys = ENV_KEY.split(',').map(k => k.trim()).filter(Boolean).map(k => ({
        id: uuidv4(),
        key: k,
        provider: 'google' as ModelProvider,
        isActive: true,
        usageLimit: 5, 
        isRateLimited: false,
        lastUsed: 0,
        model: DEFAULT_MODEL
      }));
    }
    setApiKeys(initialKeys);

    const storedSettings = localStorage.getItem(STORAGE_SETTINGS_KEY);
    let loadedSettings = settings;
    let loadedKnownModels = DEFAULT_KNOWN_MODELS;

    const storedKnownModels = localStorage.getItem(STORAGE_KNOWN_MODELS_KEY);
    if (storedKnownModels) {
        try {
            loadedKnownModels = JSON.parse(storedKnownModels);
        } catch (e) {}
    }

    if (storedSettings) {
      const parsedSettings = JSON.parse(storedSettings);
      if (parsedSettings.knownModels && !storedKnownModels) {
          loadedKnownModels = parsedSettings.knownModels;
      }
      if ('knownModels' in parsedSettings) delete parsedSettings.knownModels;
      loadedSettings = { ...settings, ...parsedSettings };
    } 
    setSettings(loadedSettings);
    setKnownModels(loadedKnownModels);

    const effectiveKeys = initialKeys.map(k => {
        if (!k.groupId) return k;
        const group = loadedSettings.keyGroups?.find(g => g.id === k.groupId);
        if (group && group.isActive === false) return { ...k, isActive: false };
        return k;
    });

    // 初始化核心 LLM 服务
    setLlmService(new LLMService(effectiveKeys, (id, errorCode, isFatal = true) => {
        setApiKeys(prev => prev.map(k => {
            if (k.id !== id) return k;
            if (isFatal) return { ...k, isActive: false, lastErrorCode: errorCode };
            else return { ...k, isRateLimited: true, lastUsed: Date.now(), lastErrorCode: errorCode };
        }));
        if (isFatal) addToast(`${t('error.key_auto_disabled', loadedSettings.language)}${errorCode ? ` (${errorCode})` : ''}`, 'error');
    }));

    // 安全锁检查
    if (loadedSettings.security.enabled) {
        const lockoutThresholdMs = (loadedSettings.security.lockoutDurationSeconds || 86400) * 1000;
        if (Date.now() - (loadedSettings.security.lastLogin || 0) > lockoutThresholdMs) setIsLocked(true);
        else setSettings({ ...loadedSettings, security: { ...loadedSettings.security, lastLogin: Date.now() } });
    }

    // 会话恢复
    const storedSessions = localStorage.getItem(STORAGE_SESSIONS_KEY);
    const storedActiveId = localStorage.getItem(STORAGE_ACTIVE_SESSION_KEY);

    if (storedSessions) {
      const parsedSessions = JSON.parse(storedSessions) as ChatSession[];
      if (parsedSessions.length > 0) {
        setSessions(parsedSessions);
        const targetId = (storedActiveId && parsedSessions.find(s => s.id === storedActiveId)) ? storedActiveId : parsedSessions[0].id;
        setActiveSessionId(targetId);
        setMessages(parsedSessions.find(s => s.id === targetId)?.messages || []);
      } else createNewSession();
    } else createNewSession();
  }, []);

  const createNewSession = () => {
    const newId = uuidv4();
    const newSession: ChatSession = {
      id: newId,
      title: t('msg.new_chat_title', settings.language),
      messages: [],
      createdAt: Date.now()
    };
    setSessions(prev => [newSession, ...prev]);
    setActiveSessionId(newId);
    setMessages([]);
  };

  /**
   * 节点 2: 数据同步
   * 监听状态变动并同步至服务层或持久化存储。
   */
  useEffect(() => {
    const effectiveKeys = apiKeys.map(k => {
        if (!k.groupId) return k;
        const group = settings.keyGroups?.find(g => g.id === k.groupId);
        if (group && group.isActive === false) return { ...k, isActive: false };
        return k;
    });

    if (llmService) llmService.updateKeys(effectiveKeys);
    localStorage.setItem(STORAGE_KEYS_KEY, JSON.stringify(apiKeys));
  }, [apiKeys, llmService, settings.keyGroups]);

  useEffect(() => {
    localStorage.setItem(STORAGE_SETTINGS_KEY, JSON.stringify(settings));
    const root = document.documentElement;
    root.classList.remove('dark', 'theme-dark', 'theme-light', 'theme-twilight', 'theme-sky', 'theme-pink', 'theme-sunrise', 'theme-lime', 'theme-panda', 'theme-chocolate', 'theme-vscode-light', 'theme-vscode-dark');
    root.classList.add(`theme-${settings.theme}`);
    if (['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme)) root.classList.add('dark');
  }, [settings]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KNOWN_MODELS_KEY, JSON.stringify(knownModels));
  }, [knownModels]);

  useEffect(() => {
    if (!activeSessionId) return;
    setSessions(prev => {
      const idx = prev.findIndex(s => s.id === activeSessionId);
      if (idx === -1) return prev;
      const updated = [...prev];
      updated[idx] = { ...updated[idx], messages };
      return updated;
    });
  }, [messages, activeSessionId]);

  useEffect(() => {
    if (sessions.length > 0) localStorage.setItem(STORAGE_SESSIONS_KEY, JSON.stringify(sessions));
  }, [sessions]);

  useEffect(() => {
    if (activeSessionId) localStorage.setItem(STORAGE_ACTIVE_SESSION_KEY, activeSessionId);
  }, [activeSessionId]);

  /**
   * 节点 3: 消息处理逻辑
   * 处理流式响应并将其分片渲染至 UI。
   */
  const triggerBotResponse = async (historyBefore: Message[], userMessage: Message) => {
    if (!llmService) return;
    setIsLoading(true);

    if (abortControllerRef.current) abortControllerRef.current.abort();
    const controller = new AbortController();
    abortControllerRef.current = controller;

    const tempBotId = uuidv4();
    const botMessage: Message = {
      id: tempBotId,
      role: Role.MODEL,
      text: '',
      timestamp: Date.now()
    };

    setMessages([...historyBefore, userMessage, botMessage]);

    const startTime = Date.now();

    try {
      const systemInstruction = settings.systemPrompts.filter(p => p.isActive).map(p => p.content).join('\n\n');
      let historyForApi = historyBefore.filter(m => m.id !== userMessage.id);

      if (settings.generation.stripThoughts) {
        historyForApi = historyForApi.map(msg => {
            if (msg.role === Role.MODEL && msg.text.includes('<think>')) {
                 const cleanText = msg.text.replace(/<think>[\s\S]*?(?:<\/think>|$)/g, '').trim();
                 return { ...msg, text: cleanText };
            }
            return msg;
        });
      }

      let contextToSend = historyForApi;
      if (settings.historyContextLimit > 0 && historyForApi.length > settings.historyContextLimit) {
          contextToSend = historyForApi.slice(-settings.historyContextLimit);
      }

      // 执行流式调用
      const { text: fullText, usedKeyIndex, provider, usedModel } = await llmService.streamChatResponse(
        '', 
        contextToSend, 
        userMessage.text, 
        userMessage.images, 
        systemInstruction,
        settings.generation,
        (chunkText) => {
           let processedChunk = chunkText;
           if (settings.scripts?.outputFilterEnabled && settings.scripts.outputFilterCode) {
               processedChunk = executeFilterScript(settings.scripts.outputFilterCode, chunkText, { role: 'model', history: [...historyBefore, userMessage] });
           }
           setMessages(prev => prev.map(msg => msg.id === tempBotId ? { ...msg, text: processedChunk } : msg));
        },
        controller.signal,
        settings.language
      );

      const executionTime = Date.now() - startTime;
      let processedFinalText = fullText;

      if (settings.scripts?.outputFilterEnabled && settings.scripts.outputFilterCode) {
          processedFinalText = executeFilterScript(settings.scripts.outputFilterCode, fullText, { role: 'model', history: [...historyBefore, userMessage] });
      }

      setMessages(prev => 
        prev.map(msg => 
          msg.id === tempBotId ? { 
              ...msg, 
              text: processedFinalText, 
              keyIndex: usedKeyIndex, 
              provider: provider, 
              model: usedModel, 
              executionTime: executionTime
          } : msg
        )
      );
    } catch (error: any) {
      if (error.message !== "Aborted by user") {
         const errorMessage: Message = {
            id: uuidv4(),
            role: Role.MODEL,
            text: `${t('action.error', settings.language)}: ${error.message || t('error.unexpected_error', settings.language)}`,
            timestamp: Date.now(),
            isError: true,
            executionTime: Date.now() - startTime
         };
         setMessages(prev => prev.filter(m => m.id !== tempBotId).concat(errorMessage));
      }
    } finally {
      setIsLoading(false);
      abortControllerRef.current = null;
    }
  };

  const handleStopGeneration = () => {
      if (abortControllerRef.current) {
          abortControllerRef.current.abort();
          abortControllerRef.current = null;
          setIsLoading(false);
      }
  };

  const handleSendMessage = async () => {
    if (!llmService || isProcessingRef.current) return;
    if (!input.trim() && inputImages.length === 0) return;

    if (apiKeys.filter(k => k.isActive).length === 0) {
      setIsSettingsOpen(true);
      return;
    }

    isProcessingRef.current = true; 

    let processedInput = input.trim();
    if (settings.scripts?.inputFilterEnabled && settings.scripts.inputFilterCode) {
        processedInput = executeFilterScript(settings.scripts.inputFilterCode, processedInput, { role: 'user', history: messages });
    }

    const newMessage: Message = {
      id: uuidv4(),
      role: Role.USER,
      text: processedInput,
      images: inputImages.length > 0 ? [...inputImages] : undefined, 
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, newMessage]);
    setInput('');
    setInputImages([]); 

    try {
        await triggerBotResponse(messages, newMessage);
    } finally {
        isProcessingRef.current = false; 
    }
  };

  /**
   * 节点 4: 加载对话功能修复与增强
   * 将对话作为新会话导入，而不是覆盖当前会话，避免用户误操作。
   */
  const handleLoadSession = (loadedMessages: any[], title?: string) => {
      handleStopGeneration();

      // 生成新的会话对象
      const newId = uuidv4();
      const newSession: ChatSession = {
          id: newId,
          title: title || t('msg.new_chat_title', settings.language),
          messages: loadedMessages,
          createdAt: Date.now()
      };

      // 插入到会话列表最前端并立即切换
      setSessions(prev => [newSession, ...prev]);
      setActiveSessionId(newId);
      setMessages(loadedMessages);
      setInput('');

      // 使用更明确的“对话已导入”提示
      addToast(t('success.chat_import', settings.language) || t('msg.config_imported', settings.language), 'success');
  };

  const handleSaveChat = () => {
    const activeSession = sessions.find(s => s.id === activeSessionId);
    const title = activeSession?.title || "Session";
    const safeTitle = title.replace(/[^a-z0-9\u4e00-\u9fa5]/gi, '_').substring(0, 50);
    const chatData = { title, date: new Date().toISOString(), messages };
    const blob = new Blob([JSON.stringify(chatData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `OmniChat-${safeTitle}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleSelectSession = (sessionId: string) => {
    if (sessionId === activeSessionId) { setIsMobileMenuOpen(false); return; }
    handleStopGeneration();
    const session = sessions.find(s => s.id === sessionId);
    if (session) {
      setActiveSessionId(sessionId);
      setMessages(session.messages);
      setInput('');
      setIsMobileMenuOpen(false);
    }
  };

  const activeKeysCount = apiKeys.filter(k => k.isActive).length;
  const currentSessionTitle = sessions.find(s => s.id === activeSessionId)?.title || t('app.title', settings.language);

  if (isLocked) return (
    <div className={`${['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme) ? 'dark' : ''}`}>
        <Suspense fallback={<div className="flex h-screen items-center justify-center bg-gray-100 dark:bg-gray-950"></div>}>
            <SecurityLock config={settings.security} onUnlock={() => setIsLocked(false)} lang={settings.language} theme={settings.theme} kirbyThemeColor={settings.kirbyThemeColor} />
        </Suspense>
    </div>
  );

  return (
    <div className={`flex h-screen font-sans ${['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme) ? 'dark' : ''}`}>
      <ToastContainer toasts={toasts} removeToast={removeToast} />
      <CustomDialog config={dialog} onClose={closeDialog} lang={settings.language} />

      <div className="flex w-full h-full bg-transparent text-gray-900 dark:text-gray-100 transition-colors duration-300">
        <Sidebar 
            sessions={sessions} activeSessionId={activeSessionId} activeKeysCount={activeKeysCount} 
            language={settings.language} theme={settings.theme} kirbyThemeColor={settings.kirbyThemeColor}
            onNewChat={() => { handleStopGeneration(); createNewSession(); setIsMobileMenuOpen(false); }} 
            onSelectSession={handleSelectSession} 
            onDeleteSession={(e, id) => {
                e.stopPropagation();
                const newSessions = sessions.filter(s => s.id !== id);
                setSessions(newSessions);
                if (activeSessionId === id) {
                   handleStopGeneration();
                   if (newSessions.length > 0) {
                     setActiveSessionId(newSessions[0].id);
                     setMessages(newSessions[0].messages);
                   } else createNewSession();
                }
            }}
            onOpenSettings={() => setIsSettingsOpen(true)}
        />

        <Suspense fallback={null}>
            <MobileMenu 
                isOpen={isMobileMenuOpen} sessions={sessions} activeSessionId={activeSessionId} language={settings.language}
                onClose={() => setIsMobileMenuOpen(false)} onNewChat={() => { handleStopGeneration(); createNewSession(); setIsMobileMenuOpen(false); }} 
                onSelectSession={handleSelectSession}
                onDeleteSession={(e, id) => {
                    e.stopPropagation();
                    const newSessions = sessions.filter(s => s.id !== id);
                    setSessions(newSessions);
                    if (activeSessionId === id) {
                       handleStopGeneration();
                       if (newSessions.length > 0) {
                         setActiveSessionId(newSessions[0].id);
                         setMessages(newSessions[0].messages);
                       } else createNewSession();
                    }
                }} 
                onOpenSettings={() => setIsSettingsOpen(true)}
            />
        </Suspense>

        <main className="flex-1 flex flex-col relative h-full min-w-0">
          <Header 
             currentSessionTitle={currentSessionTitle} isSummarizing={isSummarizing} hasMessages={messages.length > 0}
             language={settings.language} onRename={() => {
                const currentSession = sessions.find(s => s.id === activeSessionId);
                showDialog({
                    type: 'input',
                    title: t('msg.rename_chat', settings.language),
                    inputValue: currentSession?.title || '',
                    onConfirm: (newTitle) => {
                        if (newTitle && newTitle.trim()) setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: newTitle.trim() } : s));
                    }
                });
             }} 
             onSummarize={async () => {
                if (messages.length === 0 || !llmService) return;
                setIsSummarizing(true); 
                try {
                    const historyText = messages.map(m => `${m.role === Role.USER ? 'User' : 'Model'}: ${m.text}`).join('\n');
                    const prompt = t('msg.summarize_prompt', settings.language) + '\n\n' + historyText;
                    const { text } = await llmService.streamChatResponse('', [], prompt, [], undefined, settings.generation, undefined, undefined, settings.language);
                    const newTitle = text.trim().replace(/['"]/g, '').replace(/\.$/, '').replace(/\*\*/g, ''); 
                    if (newTitle) {
                        setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: newTitle } : s));
                        addToast(t('action.ok', settings.language), 'success');
                    }
                } catch (e) {
                    addToast(t('msg.summarize_error', settings.language), 'error');
                } finally { setIsSummarizing(false); }
             }}
             onOpenMobileMenu={() => setIsMobileMenuOpen(true)} 
             onNewChat={() => { handleStopGeneration(); createNewSession(); }} 
             onClearChat={() => {
                if (messages.length === 0) return;
                showDialog({
                    type: 'confirm',
                    title: t('action.clear_chat', settings.language),
                    message: t('msg.confirm_clear_chat', settings.language),
                    onConfirm: () => {
                        handleStopGeneration();
                        setMessages([]);
                        setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, messages: [] } : s));
                    }
                });
             }}
             onOpenSettings={() => setIsSettingsOpen(true)} 
             onSaveChat={handleSaveChat} 
             onLoadSession={handleLoadSession} 
             onShowToast={addToast}
          />

          <ChatInterface 
              messages={messages} isLoading={isLoading} 
              onEditMessage={(id, newText) => setMessages(prev => prev.map(msg => msg.id === id ? { ...msg, text: newText } : msg))} 
              onDeleteMessage={(id) => setMessages(prev => prev.filter(msg => msg.id !== id))} 
              onRegenerate={async (id) => {
                if (!llmService) return;
                const index = messages.findIndex(m => m.id === id);
                if (index === -1) return;
                const targetMsg = messages[index];
                if (targetMsg.role === Role.USER) {
                   await triggerBotResponse(messages.slice(0, index), targetMsg);
                } else {
                  let userMsgIndex = index - 1;
                  while (userMsgIndex >= 0 && messages[userMsgIndex].role !== Role.USER) userMsgIndex--;
                  if (userMsgIndex !== -1) await triggerBotResponse(messages.slice(0, userMsgIndex), messages[userMsgIndex]);
                }
              }} 
              language={settings.language} fontSize={settings.fontSize} 
              textWrapping={settings.textWrapping} bubbleTransparency={settings.bubbleTransparency}
              showModelName={settings.showModelName} showResponseTimer={settings.showResponseTimer} theme={settings.theme}
              kirbyThemeColor={settings.kirbyThemeColor} onShowToast={addToast} smoothAnimation={settings.smoothAnimation}
              avatarVisibility={settings.avatarVisibility}
          />

          <div className="flex-shrink-0 z-20 bg-gradient-to-t from-white via-white/90 to-transparent dark:from-black dark:via-black/90 dark:to-transparent pt-4">
             <ChatInput 
                input={input} setInput={setInput} inputImages={inputImages} setInputImages={setInputImages}
                onSend={handleSendMessage} onStop={handleStopGeneration} isLoading={isLoading} isDisabled={activeKeysCount === 0}
                fontSize={settings.fontSize} language={settings.language} activeKeysCount={activeKeysCount} showTokenUsage={settings.showTokenUsage}
                history={messages} historyLimit={settings.historyContextLimit} 
                onGetTokenCount={async (currentInput) => {
                    if (!llmService || apiKeys.length === 0) return 0;
                    const activeKey = apiKeys.find(k => k.isActive);
                    if (!activeKey) return 0;
                    return await llmService.countTokens(activeKey, messages, currentInput, settings.systemPrompts.filter(p => p.isActive).map(p => p.content).join('\n\n'));
                }} 
                theme={settings.theme}
             />
             <div className="text-center text-[10px] text-gray-400 dark:text-gray-600 pb-1 select-none">
                {t('footer.ai_generated', settings.language)}{APP_VERSION}
             </div>
          </div>
        </main>

        <Suspense fallback={null}>
            <SettingsModal 
                isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} apiKeys={apiKeys} onUpdateKeys={setApiKeys} 
                settings={settings} onUpdateSettings={setSettings} llmService={llmService} onShowToast={addToast}
                onShowDialog={showDialog} knownModels={knownModels} onUpdateKnownModels={setKnownModels}
            />
        </Suspense>
      </div>
    </div>
  );
};

export default App;
